def generate(skip_compile=False):
    generation_config = GenerationConfig.from_pretrained(model_path)
    if not skip_compile:
        neuron_config = MoENeuronConfig(tp_degree=4, batch_size=1, max_context_length=128, seq_len=1024, on_device_sampling_config=OnDeviceSamplingConfig(do_sample=True, temperature=0.6, top_k=20, top_p=0.95), enable_bucketing=False, flash_decoding_enabled=False)
        config = Qwen3MoeInferenceConfig(neuron_config, load_config=load_pretrained_config(model_path))
        tokenizer = AutoTokenizer.from_pretrained(model_path, padding_side='right')
        tokenizer.pad_token = tokenizer.eos_token
        print('\nCompiling and saving model...')
        model = NeuronQwen3MoeForCausalLM(model_path, config)
        model.compile(traced_model_path)
        tokenizer.save_pretrained(traced_model_path)
    print('\nLoading model from compiled checkpoint...')
    model = NeuronQwen3MoeForCausalLM(traced_model_path)
    model.load(traced_model_path)
    tokenizer = AutoTokenizer.from_pretrained(traced_model_path)
    print('\nGenerating outputs...')
    prompt = 'Give me a short introduction to large language models.'
    messages = [{'role': 'user', 'content': prompt}]
    text = tokenizer.apply_chat_template(messages, tokenize=False, add_generation_prompt=True, enable_thinking=True)
    inputs = tokenizer([text], padding=True, return_tensors='pt')
    generation_model = HuggingFaceGenerationAdapter(model)
    outputs = generation_model.generate(inputs.input_ids, generation_config=generation_config, attention_mask=inputs.attention_mask, max_length=model.config.neuron_config.max_length)
    output_tokens = tokenizer.batch_decode(outputs, skip_special_tokens=True, clean_up_tokenization_spaces=False)
    print('Generated outputs:')
    for i, output_token in enumerate(output_tokens):
        print(f'Output {i}: {output_token}')

