def is_hbm_buffer(tensor: nl.ndarray) -> bool:
    return tensor.buffer in (nl.hbm, nl.shared_hbm, nl.private_hbm)

def get_program_sharding_info() -> Tuple[int, int, int]:
    grid_ndim = nl.program_ndim()
    n_prgs, prg_id = (
        (nl.num_programs(axes=0), nl.program_id(axis=0)) if grid_ndim != 0 else (1, 0)
    )
    return grid_ndim, n_prgs, prg_id

def get_verified_program_sharding_info(
    kernel_name: str = "",
    allowed_ndims: Optional[Tuple[int, ...]] = None,
    max_sharding: Optional[int] = None,
) -> Tuple[int, int, int]:
    grid_ndim, n_prgs, prg_id = get_program_sharding_info()
    ndim_check = allowed_ndims is None or (
        grid_ndim == allowed_ndims[0] if len(allowed_ndims) == 1 else False
    )
    return grid_ndim, n_prgs, prg_id

import os
import sys
from typing import Optional

class LogLevel(Enum):
    DEBUG = 0
    INFO = 1
    WARN = 2
    ERROR = 3
    OFF = 999

    @staticmethod
    def from_string(level: str) -> "LogLevel":
        return _STRING_TO_LOG_LEVEL[level]

_STRING_TO_LOG_LEVEL = {
    "DEBUG": LogLevel.DEBUG,
    "INFO": LogLevel.INFO,
    "WARN": LogLevel.WARN,
    "ERROR": LogLevel.ERROR,
    "OFF": LogLevel.OFF,
}

_DEFAULT_LOG_LEVEL = LogLevel.INFO

class Logger(nl.NKIObject):
    def __init__(self, name: str, level: LogLevel = _DEFAULT_LOG_LEVEL):
        self.name = name
        self.level = level

    def _should_log(self, level: LogLevel) -> bool:
        return level.value >= self.level.value

    def is_enabled_for(self, level: LogLevel) -> bool:
        return self._should_log(level)

    def _print(self, msg: str, prefix: str = ""):
        name_prefix = f"[{self.name}] " if self.name else ""
        print(f"{prefix}{name_prefix}{msg}")

    def debug(self, msg: str):
        if self._should_log(LogLevel.DEBUG):
            self._print(msg, prefix="[DEBUG] ")

    def info(self, msg: str):
        if self._should_log(LogLevel.INFO):
            self._print(msg, prefix="[INFO] ")

    def warn(self, msg: str):
        if self._should_log(LogLevel.WARN):
            self._print(msg, prefix="[WARN] ")

    def error(self, msg: str):
        if self._should_log(LogLevel.ERROR):
            self._print(msg, prefix="[ERROR] ")

_ENV_VAR_NAME = "NKILIB_LOG_LEVEL"
_ENV_VAR_PREFIX = _ENV_VAR_NAME + "_"

def _init_from_env_py() -> tuple[Optional[LogLevel], dict[str, LogLevel]]:
    specific_levels = {}
    global_level = None

    for key, value in os.environ.items():

        if key == _ENV_VAR_NAME:
            try:
                global_level = LogLevel.from_string(value.upper())
            except KeyError:
                print(f"Warning: Invalid {_ENV_VAR_NAME}='{value}'", file=sys.stderr)

        elif key.startswith(_ENV_VAR_PREFIX):
            logger_name = key.removeprefix(_ENV_VAR_PREFIX)
            try:
                specific_levels[logger_name] = LogLevel.from_string(value.upper())
            except KeyError:
                print(
                    f"Warning: Invalid log level '{value}' for {logger_name}",
                    file=sys.stderr,
                )

    return global_level, specific_levels

_ENV_GLOBAL_LOG_LEVEL, _ENV_LOG_LEVELS = _init_from_env_py()

def get_logger(name: str, level: LogLevel = _DEFAULT_LOG_LEVEL) -> Logger:

    env_log_level = _ENV_LOG_LEVELS.get(name)
    if env_log_level != None:
        return Logger(name, env_log_level)

    if _ENV_GLOBAL_LOG_LEVEL != None:
        return Logger(name, _ENV_GLOBAL_LOG_LEVEL)

    return Logger(name, level)

logger = get_logger("")

from typing import Tuple

from nki.language import NKIObject

class TiledRangeIterator(NKIObject):

    def __init__(self, tile_size: int, tile_index: int, start_offset: int):
        self.size = tile_size
        self.index = tile_index
        self.start_offset = start_offset

    def __repr__(self) -> str:
        return f"TiledRangeIterator(size={self.size}, index={self.index}, start_offset={self.start_offset})"

def TiledRange(size, tile_size: int) -> Tuple[TiledRangeIterator, ...]:
    if isinstance(size, TiledRangeIterator):

        total_size = size.size
        base_offset = size.start_offset
    else:
        total_size = size
        base_offset = 0

    num_tiles = math.ceil(total_size / tile_size)

    iterators = []
    for i in range(num_tiles):
        relative_offset = i * tile_size

        current_tile_size = min(tile_size, total_size - relative_offset)

        iterators.append(
            TiledRangeIterator(current_tile_size, i, base_offset + relative_offset)
        )

    return tuple(iterators)

