@dataclass
class MLPExpertParameters(NKIObject):

    expert_affinities: nl.ndarray
    expert_index: nl.ndarray
    expert_affinities_scaling_mode: ExpertAffinityScaleMode = (
        ExpertAffinityScaleMode.POST_SCALE
    )

@dataclass
class MLPBiasParameters(NKIObject):

    gate_proj_bias_tensor: Optional[nl.ndarray]
    up_proj_bias_tensor: Optional[nl.ndarray]
    down_proj_bias_tensor: Optional[nl.ndarray]

    def __init__(
        self,
        gate_proj_bias_tensor: Optional[nl.ndarray],
        up_proj_bias_tensor: Optional[nl.ndarray],
        down_proj_bias_tensor: Optional[nl.ndarray],
    ):
        self.gate_proj_bias_tensor = gate_proj_bias_tensor
        self.up_proj_bias_tensor = up_proj_bias_tensor
        self.down_proj_bias_tensor = down_proj_bias_tensor

@dataclass
class MLPNormalizationParameters(NKIObject):

    normalization_type: NormType
    normalization_weights_tensor: Optional[nl.ndarray]
    normalization_bias_tensor: Optional[nl.ndarray]

    def __init__(
        self,
        normalization_type: NormType,
        normalization_weights_tensor: Optional[nl.ndarray],
        normalization_bias_tensor: Optional[nl.ndarray],
    ):
        if normalization_type == NormType.NO_NORM:
            self.normalization_type = NormType.NO_NORM
            self.normalization_weights_tensor = None
            self.normalization_bias_tensor = None
        else:
            self.normalization_type = normalization_type
            self.normalization_weights_tensor = normalization_weights_tensor
            self.normalization_bias_tensor = normalization_bias_tensor

@dataclass
class MoEGateParameters(NKIObject):

    gamma: Optional[nl.ndarray]                                                
    router_weights: nl.ndarray                         
    router_bias: Optional[nl.ndarray]                               
    router_act_fn: RouterActFnType                      
    router_pre_norm: bool                                 
    norm_topk_prob: bool                                 
    router_mm_dtype: nki.dtype                           
    hidden_actual: Optional[int]                                  
    top_k: int                                     

    def __init__(
        self,
        router_weights: nl.ndarray,
        top_k: int,
        gamma: Optional[nl.ndarray] = None,
        router_bias: Optional[nl.ndarray] = None,
        router_act_fn: RouterActFnType = RouterActFnType.SIGMOID,
        router_pre_norm: bool = True,
        norm_topk_prob: bool = False,
        router_mm_dtype: nki.dtype = nl.bfloat16,
        hidden_actual: Optional[int] = None,
    ):
        self.gamma = gamma
        self.router_weights = router_weights
        self.top_k = top_k
        self.router_bias = router_bias
        self.router_act_fn = router_act_fn
        self.router_pre_norm = router_pre_norm
        self.norm_topk_prob = norm_topk_prob
        self.router_mm_dtype = router_mm_dtype
        self.hidden_actual = hidden_actual

@dataclass
class MLPParameters(NKIObject):

    hidden_tensor: nl.ndarray
    gate_proj_weights_tensor: nl.ndarray
    up_proj_weights_tensor: nl.ndarray
    down_proj_weights_tensor: nl.ndarray
    activation_fn: ActFnType
    output_dtype: nki.dtype
    norm_params: Optional[MLPNormalizationParameters]
    bias_params: Optional[MLPBiasParameters]
    expert_params: Optional[MLPExpertParameters]
    gate_params: Optional[MoEGateParameters]
    router_probs: Optional[
        nl.ndarray
    ]                                                          
    router_matmul_weights: Optional[
        nl.ndarray
    ]                                                             
    router_bias: Optional[nl.ndarray]                                               
    router_act_fn: Optional[
        RouterActFnType
    ]                                               
    norm_topk_prob: bool                                               
    gamma: Optional[
        nl.ndarray
    ]                                                              
    hidden_actual: Optional[
        int
    ]                                                           
    normed_hbm: Optional[
        nl.ndarray
    ]                                                                          
    top_k: Optional[int]                                               
    name_prefix: str                                          
    eps: float
    batch_size: int
    sequence_len: int
    hidden_size: int
    intermediate_size: int
    input_in_sbuf: bool
    store_output_in_sbuf: bool
    use_tkg_gate_up_proj_column_tiling: bool
    use_tkg_down_proj_column_tiling: bool
    gate_clamp_lower_limit: Optional[float]
    gate_clamp_upper_limit: Optional[float]
    up_clamp_lower_limit: Optional[float]
    up_clamp_upper_limit: Optional[float]
    down_weight_transposed: bool

    def __init__(
        self,
        hidden_tensor: nl.ndarray,
        gate_proj_weights_tensor: nl.ndarray,
        up_proj_weights_tensor: nl.ndarray,
        down_proj_weights_tensor: nl.ndarray,
        normalization_weights_tensor: Optional[nl.ndarray] = None,
        gate_proj_bias_tensor: Optional[nl.ndarray] = None,
        up_proj_bias_tensor: Optional[nl.ndarray] = None,
        down_proj_bias_tensor: Optional[nl.ndarray] = None,
        normalization_bias_tensor: Optional[nl.ndarray] = None,
        activation_fn: ActFnType = ActFnType.SiLU,
        normalization_type: NormType = NormType.NO_NORM,
        output_dtype: nki.dtype = nl.bfloat16,
        store_output_in_sbuf: bool = False,
        eps: float = 1e-6,
        use_tkg_gate_up_proj_column_tiling: bool = False,
        use_tkg_down_proj_column_tiling: bool = False,
        gate_clamp_lower_limit: Optional[float] = None,
        gate_clamp_upper_limit: Optional[float] = None,
        up_clamp_lower_limit: Optional[float] = None,
        up_clamp_upper_limit: Optional[float] = None,
        down_weight_transposed: bool = False,
        expert_params: Optional[MLPExpertParameters] = None,
        gate_params: Optional[MoEGateParameters] = None,
        router_probs: Optional[nl.ndarray] = None,
        router_matmul_weights: Optional[nl.ndarray] = None,
        router_bias: Optional[nl.ndarray] = None,
        router_act_fn: Optional[RouterActFnType] = None,
        norm_topk_prob: bool = False,
        gamma: Optional[nl.ndarray] = None,
        hidden_actual: Optional[int] = None,
        normed_hbm: Optional[nl.ndarray] = None,
        top_k: Optional[int] = None,
        name_prefix: str = "",
    ):
        self.input_in_sbuf = hidden_tensor.buffer == nl.sbuf
        if self.input_in_sbuf:

            kernel_assert(
                len(hidden_tensor.shape) == 3,
                "SBUF input must have 3D shape [H0, T, H1]",
            )
            _, T, _ = hidden_tensor.shape
            self.batch_size = 1
            self.sequence_len = T
            self.hidden_size = down_proj_weights_tensor.shape[-1]
        elif len(hidden_tensor.shape) == 3:           
            self.batch_size = hidden_tensor.shape[0]
            self.sequence_len = hidden_tensor.shape[1]
            self.hidden_size = hidden_tensor.shape[2]
        else:        
            self.batch_size = 1
            self.sequence_len = hidden_tensor.shape[0]
            self.hidden_size = hidden_tensor.shape[1]

        self.down_weight_transposed = down_weight_transposed
        if len(down_proj_weights_tensor.shape) == 3:
            if down_weight_transposed:

                self.intermediate_size = down_proj_weights_tensor.shape[2]
                kernel_assert(
                    down_proj_weights_tensor.shape[1] == self.hidden_size,
                    "unexpected down project weight shape {down_proj_weights_tensor.shape}",
                )
            else:

                self.intermediate_size = down_proj_weights_tensor.shape[1]
                kernel_assert(
                    down_proj_weights_tensor.shape[2] == self.hidden_size,
                    "unexpected down project weight shape {down_proj_weights_tensor.shape}",
                )
        elif len(down_proj_weights_tensor.shape) == 2:        
            self.intermediate_size = down_proj_weights_tensor.shape[0]
            kernel_assert(
                down_proj_weights_tensor.shape[1] == self.hidden_size,
                "unexpected down project weight shape {down_proj_weights_tensor.shape}",
            )

        self.hidden_tensor = hidden_tensor
        self.gate_proj_weights_tensor = gate_proj_weights_tensor
        self.up_proj_weights_tensor = up_proj_weights_tensor
        self.down_proj_weights_tensor = down_proj_weights_tensor
        self.activation_fn = activation_fn
        self.output_dtype = output_dtype
        self.eps = eps
        self.store_output_in_sbuf = store_output_in_sbuf
        self.use_tkg_gate_up_proj_column_tiling = use_tkg_gate_up_proj_column_tiling
        self.use_tkg_down_proj_column_tiling = use_tkg_down_proj_column_tiling
        self.gate_clamp_lower_limit = gate_clamp_lower_limit
        self.gate_clamp_upper_limit = gate_clamp_upper_limit
        self.up_clamp_lower_limit = up_clamp_lower_limit
        self.up_clamp_upper_limit = up_clamp_upper_limit

        self.norm_params = MLPNormalizationParameters(
            normalization_type, normalization_weights_tensor, normalization_bias_tensor
        )
        self.bias_params = MLPBiasParameters(
            gate_proj_bias_tensor, up_proj_bias_tensor, down_proj_bias_tensor
        )
        self.expert_params = expert_params
        self.gate_params = gate_params
        self.router_probs = router_probs
        self.router_matmul_weights = router_matmul_weights
        self.router_bias = router_bias
        self.router_act_fn = router_act_fn
        self.norm_topk_prob = norm_topk_prob
        self.gamma = gamma
        self.hidden_actual = hidden_actual
        self.normed_hbm = normed_hbm
        self.top_k = top_k
        self.name_prefix = name_prefix

@dataclass
class LogEntry(nl.NKIObject):

    msg: str
    depth: int
    is_stack: bool                                  
    is_scope_boundary: bool = False                             

class TreeLogger(nl.NKIObject):

    def __init__(self, name: str, logger: Logger):
        self.name = name
        self.logger = logger
        self.stack_logs = []

    def log(self, msg: str, depth: int, is_scope_boundary: bool = False):
        self.stack_logs.append(LogEntry(msg, depth, True, is_scope_boundary))

    def _has_depth_after(self, logs, start_idx: int, target_depth: int) -> bool:
        for j in range(start_idx, len(logs)):
            if logs[j].depth == target_depth:
                return True
        return False

    def _tree_prefix(self, depth: int, is_last: bool, parent_continues) -> str:
        if depth == 0:
            return ""
        prefix = ""
        for i in range(depth - 1):
            if i < len(parent_continues) and parent_continues[i]:
                prefix += "│   "
            else:
                prefix += "    "
        if is_last:
            prefix += "└── "
        else:
            prefix += "├── "
        return prefix

    def flush(self):

        if not self.stack_logs:
            return

        self.logger.info(f"[{self.name}] Allocations:")
        self._print_tree(self.stack_logs)
        self.stack_logs.clear()

    def _print_tree(self, logs):

        is_last = []
        for i in range(len(logs)):
            is_last.append(True)

        for i in range(len(logs)):
            depth_i = logs[i].depth
            for j in range(i + 1, len(logs)):
                depth_j = logs[j].depth
                if depth_j < depth_i:
                    break
                if depth_j == depth_i:
                    is_last[i] = False
                    break

        for i in range(len(logs)):
            entry = logs[i]
            prefix = ""
            if entry.depth > 0:
                for d in range(entry.depth - 1):
                    prefix = prefix + "│   "
                if is_last[i]:
                    prefix = prefix + "└── "
                else:
                    prefix = prefix + "├── "
            print(f"    {prefix}{entry.msg}")

def sizeinbytes(dtype):
    if str(dtype) == str(nl.float32):
        return 4
    elif (
        str(dtype) == str(nl.bfloat16)
        or str(dtype) == str(nl.float16)
        or str(dtype) == str(nl.uint16)
        or str(dtype) == str(nl.int16)
    ):
        return 2
    elif (
        str(dtype) == str(nl.int8)
        or str(dtype) == str(nl.uint8)
        or str(dtype)
        in ["float8e4", "float8_e4m3", "float8_e4m3fn", "float8e5", "float8_e5m2"]
    ):
        return 1
    elif str(dtype) == str(nl.int32) or str(dtype) == str(nl.uint32):
        return 4
    elif str(dtype) == str(nl.float4_e2m1fn_x4):
        return 2
    elif str(dtype) == str(nl.float8_e4m3fn_x4) or str(dtype) == str(nl.float8_e5m2_x4):
        return 4
    kernel_assert(False, f"dtype size unknown! {dtype}")

def align_to(value, alignment):

    return ((value + alignment - 1) // alignment) * alignment

def num_elts(shape):
    res = 1
    for i in range(len(shape)):
        res = res * shape[i]
    return res

@dataclass
class Scope(nl.NKIObject):
    starting_addr: int
    num_sections: int
    name: str

    cur_section_id: int = 0
    min_independent_addr: int | None = None

    def update_min_independent_addr(self, new_address):
        self.min_independent_addr = max(self.min_independent_addr, new_address)

    def __post_init__(self):
        kernel_assert(
            self.min_independent_addr == None,
            "`min_independent_addr` should not be initialized",
        )
        self.min_independent_addr = self.starting_addr

class BufferManager(nl.NKIObject):
    def __init__(
        self,
        sb_lower_bound: int,
        sb_upper_bound: int,
        logger: Optional[Logger] = None,
        use_auto_alloc: bool = False,
        default_stack_alloc: bool = True,
    ):
        self.lower_bound = sb_lower_bound
        self.upper_bound = sb_upper_bound
        self.stack_curr_addr = sb_lower_bound
        self.heap_curr_addr = sb_upper_bound
        self.use_auto_alloc = use_auto_alloc
        self.default_stack_alloc = default_stack_alloc
        self.logger = logger
        if self.logger == None:
            self.logger = get_logger("SBM")
        self.scopes: list[Scope] = []
        self.heap = []
        self.heap_names = []
        self.tree_logger = TreeLogger("SBM", self.logger)

        self.max_stack_usage = 0
        self.max_heap_usage = 0
        self.max_combined_usage = 0
        self.total_stack_allocs = 0
        self.total_heap_allocs = 0

        total_size = sb_upper_bound - sb_lower_bound
        self.logger.info(
            f"SBM initialized: range=[{sb_lower_bound}, {sb_upper_bound}), size={total_size} B"
        )
        self.logger.debug(
            f"SBM config: auto_alloc={use_auto_alloc}, default_stack={default_stack_alloc}, "
            f"stack_start={sb_lower_bound}, heap_start={sb_upper_bound}"
        )
        self.prefix = ""

    def _get_prefixed_name(self, name):
        if name is None:
            return None
        return f"{self.prefix}{name}"

    def _update_stats(self):
        stack_usage = self.stack_curr_addr - self.lower_bound
        heap_usage = self.upper_bound - self.heap_curr_addr
        combined = stack_usage + heap_usage
        if stack_usage > self.max_stack_usage:
            self.max_stack_usage = stack_usage
        if heap_usage > self.max_heap_usage:
            self.max_heap_usage = heap_usage
        if combined > self.max_combined_usage:
            self.max_combined_usage = combined

    def _print_stats(self):
        total = self.upper_bound - self.lower_bound
        free = total - self.max_combined_usage
        pct = (self.max_combined_usage * 100) // total
        self.logger.info(
            f"[SBM] SB memory statistics: max_usage={self.max_combined_usage} B ({pct}%), free={free} B, stack={self.max_stack_usage} B ({self.total_stack_allocs} allocs), heap={self.max_heap_usage} B ({self.total_heap_allocs} allocs)"
        )

    def is_auto_alloc(self):
        return self.use_auto_alloc

    def set_auto_alloc(self, value: bool):
        self.use_auto_alloc = value

    def is_default_stack_alloc(self):
        return self.default_stack_alloc

    def is_default_heap_alloc(self):
        return not self.default_stack_alloc

    def open_scope(self, interleave_degree=1, name=""):
        self.scopes.append(Scope(self.stack_curr_addr, interleave_degree, name))
        scope_name = f"'{name}'" if name else "(unnamed)"
        self.tree_logger.log(
            f"▶ SCOPE {scope_name} [interleave={interleave_degree}] @ {self.stack_curr_addr}",
            len(self.scopes) - 1,
            is_scope_boundary=True,
        )

    def increment_section(self):
        top_scope = self.scopes[-1]
        top_scope.cur_section_id = top_scope.cur_section_id + 1
        if top_scope.cur_section_id == top_scope.num_sections:
            top_scope.cur_section_id = 0
            self.stack_curr_addr = top_scope.starting_addr

            if len(self.scopes) >= 2:
                self.scopes[-2].update_min_independent_addr(
                    top_scope.min_independent_addr
                )
            top_scope.min_independent_addr = top_scope.starting_addr

            self.tree_logger.log(
                f"↻ section: 0/{top_scope.num_sections} @ {self.stack_curr_addr}",
                len(self.scopes),
            )
        else:

            self.stack_curr_addr = self.scopes[-1].min_independent_addr
            self.tree_logger.log(
                f"↳ section: {top_scope.cur_section_id}/{top_scope.num_sections} @ {self.stack_curr_addr}",
                len(self.scopes),
            )

    def close_scope(self):
        closing_scope = self.scopes[-1]
        freed_bytes = self.stack_curr_addr - closing_scope.starting_addr
        self.stack_curr_addr = closing_scope.starting_addr
        self.scopes.pop()
        scope_name = f"'{closing_scope.name}'" if closing_scope.name else "(unnamed)"
        self.tree_logger.log(
            f"◀ END {scope_name} freed={freed_bytes} B",
            len(self.scopes),
            is_scope_boundary=True,
        )

        if not self.scopes:

            self.tree_logger.flush()
            self._print_stats()
        else:

            self.scopes[-1].update_min_independent_addr(
                closing_scope.min_independent_addr
            )

    def alloc(
        self, shape, dtype, buffer=nl.sbuf, name=None, base_partition=0, align=None
    ):
        if buffer in (nl.hbm, nl.shared_hbm, nl.private_hbm):
            tensor_name = self._get_prefixed_name(name)
            return nl.ndarray(shape, dtype=dtype, buffer=buffer, name=tensor_name)

        if self.default_stack_alloc:
            return self.alloc_stack(
                shape,
                dtype,
                buffer=buffer,
                name=name,
                base_partition=base_partition,
                align=align,
            )
        else:
            return self.alloc_heap(
                shape,
                dtype,
                buffer=buffer,
                name=name,
                base_partition=base_partition,
                align=align,
            )

    def alloc_stack(
        self, shape, dtype, buffer=nl.sbuf, name=None, base_partition=0, align=None
    ):
        kernel_assert(
            buffer == nl.sbuf, "alloc_stack is only supported for SBUF tensors"
        )
        N = num_elts(shape[1:])
        bytes_per_partition = N * sizeinbytes(dtype)

        if (
            not self.is_auto_alloc()
            and self.stack_curr_addr + bytes_per_partition > self.heap_curr_addr
        ):
            available = self.heap_curr_addr - self.stack_curr_addr
            self.logger.error(
                f"Stack OOM: requested={bytes_per_partition} B, available={available} B"
            )
            self.logger.debug(
                f"Allocation failure: name={name}, shape={shape}, dtype={dtype}, size={bytes_per_partition} B, "
                f"stack_addr={self.stack_curr_addr}, heap_addr={self.heap_curr_addr}, "
                f"range=[{self.lower_bound}, {self.upper_bound})"
            )
            self.tree_logger.flush()
            self._print_stats()
            kernel_assert(False, "Stack out of memory")

        if not self.scopes:
            self.logger.error("Cannot allocate in stack without an open scope")
            self.logger.debug(
                f"Stack state: no open scopes, stack_addr={self.stack_curr_addr}"
            )
            kernel_assert(False, "Cannot allocate in stack without an open scope")

        if align == None:
            align = sizeinbytes(dtype)
        self.stack_curr_addr = align_to(self.stack_curr_addr, align)
        tensor_name = self._get_prefixed_name(name)
        if self.use_auto_alloc:
            mloc = nl.ndarray(shape=shape, dtype=dtype, buffer=buffer, name=tensor_name)
        else:
            mloc = nl.ndarray(
                shape=shape,
                dtype=dtype,
                buffer=buffer,
                name=tensor_name,
                address=(base_partition, self.stack_curr_addr),
            )
        addr_start = self.stack_curr_addr
        self.stack_curr_addr = self.stack_curr_addr + bytes_per_partition
        self.scopes[-1].update_min_independent_addr(
            self.stack_curr_addr
        )                                    

        self.total_stack_allocs = self.total_stack_allocs + 1
        self._update_stats()
        self.tree_logger.log(
            f"{tensor_name or '(unnamed)'}: {bytes_per_partition} B @ {addr_start} {shape} {dtype}",
            len(self.scopes),
        )
        self.logger.debug(
            f"Stack allocation: name={name}, shape={shape}, dtype={dtype}, size={bytes_per_partition} B, "
            f"addr_range=[{addr_start}, {self.stack_curr_addr}), "
            f"partition={base_partition}, align={align}, scope_depth={len(self.scopes)}, "
            f"free_space={self.heap_curr_addr - self.stack_curr_addr} B"
        )

        return mloc

    def alloc_heap(
        self, shape, dtype, buffer=nl.sbuf, name=None, base_partition=0, align=None
    ):
        kernel_assert(
            buffer == nl.sbuf, "alloc_heap is only supported for SBUF tensors"
        )
        N = num_elts(shape[1:])
        bytes_per_partition = N * sizeinbytes(dtype)

        if (
            not self.is_auto_alloc()
            and self.stack_curr_addr + bytes_per_partition > self.heap_curr_addr
        ):
            available = self.heap_curr_addr - self.stack_curr_addr
            self.logger.error(
                f"Heap OOM: requested={bytes_per_partition} B, available={available} B"
            )
            self.logger.debug(
                f"Allocation failure: name={name}, shape={shape}, dtype={dtype}, size={bytes_per_partition} B, "
                f"stack_addr={self.stack_curr_addr}, heap_addr={self.heap_curr_addr}, "
                f"range=[{self.lower_bound}, {self.upper_bound})"
            )
            self.tree_logger.flush()
            self._print_stats()
            kernel_assert(False, "Heap out of memory")

        if align != None:
            self.heap_curr_addr = align_to(self.heap_curr_addr - (align - 1), align)
        base_addr = self.heap_curr_addr - bytes_per_partition
        self.heap_curr_addr -= bytes_per_partition
        self.heap_curr_addr = align_to(
            self.heap_curr_addr - 3, 4
        )                                        

        tensor_name = self._get_prefixed_name(name)
        if self.use_auto_alloc:
            mloc = nl.ndarray(shape=shape, dtype=dtype, buffer=buffer, name=tensor_name)
        else:
            mloc = nl.ndarray(
                shape=shape,
                dtype=dtype,
                buffer=buffer,
                name=tensor_name,
                address=(base_partition, base_addr),
            )
        self.heap.append(mloc)
        self.heap_names.append(tensor_name or "(unnamed)")
        self.total_heap_allocs = self.total_heap_allocs + 1
        self._update_stats()
        self.tree_logger.log(
            f"[HEAP+] {tensor_name or '(unnamed)'}: {bytes_per_partition} B @ {self.heap_curr_addr} {shape} {dtype}",
            len(self.scopes),
        )
        self.logger.debug(
            f"Heap allocation: name={name}, shape={shape}, dtype={dtype}, size={bytes_per_partition} B, "
            f"addr_range=[{self.heap_curr_addr}, {base_addr}), partition={base_partition}, "
            f"heap_depth={len(self.heap)}, free_space={self.heap_curr_addr - self.stack_curr_addr} B"
        )

        return mloc

    def pop_heap(self):
        if not self.heap:
            self.logger.error("Heap underflow: pop called on empty heap")
            kernel_assert(False, "Heap underflow: pop called on empty heap")

        heap_top = self.heap[-1]
        heap_name = self.heap_names[-1]
        N = num_elts(heap_top.shape[1:])

        bytes_per_partition = N * sizeinbytes(heap_top.dtype)
        self.heap_curr_addr = self.heap_curr_addr + bytes_per_partition
        self.heap_curr_addr = align_to(self.heap_curr_addr - 3, 4)
        self.heap.pop()
        self.heap_names.pop()
        self.tree_logger.log(
            f"[HEAP-] FREE {heap_name}: {bytes_per_partition} B, remaining={len(self.heap)}",
            len(self.scopes),
        )

    def get_total_space(self):
        return self.upper_bound - self.lower_bound

    def get_free_space(self):
        return self.heap_curr_addr - self.stack_curr_addr

    def get_used_space(self):
        return self.get_total_space() - self.get_free_space()

    def get_stack_curr_addr(self):
        if self.use_auto_alloc:
            self.logger.error(
                "get_stack_curr_addr() is not supported in auto-allocation mode."
            )
            kernel_assert(
                False, "get_stack_curr_addr() is not supported in auto-allocation mode"
            )
        return self.stack_curr_addr

    def get_heap_curr_addr(self):
        if self.use_auto_alloc:
            self.logger.error(
                "get_heap_curr_addr() is not supported in auto-allocation mode."
            )
            kernel_assert(
                False, "get_heap_curr_addr() is not supported in auto-allocation mode"
            )
        return self.heap_curr_addr

    def align_stack_curr_addr(self, align=32):
        if self.use_auto_alloc:
            self.logger.error(
                "align_stack_curr_addr() is not supported in auto-allocation mode."
            )
            kernel_assert(
                False,
                "align_stack_curr_addr() is not supported in auto-allocation mode",
            )
        self.stack_curr_addr = align_to(self.stack_curr_addr, align)

    def set_name_prefix(self, prefix):
        self.prefix = prefix

    def get_name_prefix(self):
        return self.prefix

    def flush_logs(self):
        self.tree_logger.flush()

SbufManager = BufferManager

from typing import Dict, List, Optional, Tuple, Union

logger = Logger("TensorView")

class TensorView(nl.NKIObject):

    base_tensor: nl.ndarray
    shape: Tuple[int, ...]
    strides: Tuple[int, ...]
    offset: int
    dtype: object
    scalar_offset: nl.ndarray = None
    indirect_dim: Optional[int] = None

    def get_dim(self) -> int:
        return len(self.shape)

    def is_sbuf(self) -> bool:
        return self.base_tensor.buffer == nl.sbuf

    def is_hbm(self) -> bool:
        return is_hbm_buffer(self.base_tensor)

    @staticmethod
    def get_trivial_strides(
        shape: Tuple[int, ...], base_stride: int = 1
    ) -> Tuple[int, ...]:

        strides = [base_stride]
        for i in range(1, len(shape)):

            strides.append(strides[i - 1] * shape[len(shape) - i])

        ret = []
        for i in range(len(shape)):
            ret.append(strides[len(shape) - i - 1])
        return tuple(ret)

    def __init__(self, base_tensor: nl.ndarray):
        kernel_assert(base_tensor is not None, "Base tensor cannot be None")

        if isinstance(base_tensor, TensorView):
            self.base_tensor = base_tensor.base_tensor
            self.shape = base_tensor.shape
            self.strides = base_tensor.strides
            self.offset = base_tensor.offset
            self.dtype = base_tensor.dtype
            self.scalar_offset = base_tensor.scalar_offset
            self.vector_offset = base_tensor.vector_offset
            self.indirect_dim = base_tensor.indirect_dim
        else:
            self.base_tensor = base_tensor
            self.shape = tuple(base_tensor.shape)
            self.strides = TensorView.get_trivial_strides(self.shape)
            self.offset = 0
            self.dtype = base_tensor.dtype
            self.scalar_offset = None
            self.vector_offset = None
            self.indirect_dim = None

    def reinterpret_cast(self, new_dtype) -> "TensorView":
        old_size = sizeinbytes(self.dtype)
        new_size = sizeinbytes(new_dtype)

        if old_size == new_size:
            return self._copy(dtype=new_dtype)

        kernel_assert(
            self.indirect_dim is None,
            "reinterpret_cast with different element sizes is not supported after dynamic/vector select",
        )

        last_dim = self.get_dim() - 1
        last_dim_size = self.shape[last_dim]

        if new_size > old_size:

            ratio = new_size // old_size
            kernel_assert(
                self.strides[last_dim] == 1,
                f"reinterpret_cast to larger dtype requires contiguous last dimension (stride=1), got stride={self.strides[last_dim]}",
            )
            kernel_assert(
                last_dim_size % ratio == 0,
                f"Last dimension size {last_dim_size} not divisible by dtype size ratio {ratio}",
            )
            kernel_assert(
                self.offset % ratio == 0,
                f"Offset {self.offset} not divisible by dtype size ratio {ratio}",
            )

            new_strides = []
            for i in range(last_dim):
                kernel_assert(
                    self.strides[i] % ratio == 0,
                    f"Stride at dimension {i} ({self.strides[i]}) not divisible by dtype size ratio {ratio}",
                )
                new_strides.append(self.strides[i] // ratio)
            new_strides.append(1)
            new_shape = self.shape[:last_dim] + (last_dim_size // ratio,)
            new_offset = self.offset // ratio
        else:

            ratio = old_size // new_size
            kernel_assert(
                self.strides[last_dim] == 1,
                f"reinterpret_cast to smaller dtype requires contiguous last dimension (stride=1), got stride={self.strides[last_dim]}",
            )
            new_strides = []
            for i in range(last_dim):
                new_strides.append(self.strides[i] * ratio)
            new_strides.append(1)
            new_shape = self.shape[:last_dim] + (last_dim_size * ratio,)
            new_offset = self.offset * ratio

        return self._copy(
            shape=new_shape, strides=new_strides, offset=new_offset, dtype=new_dtype
        )

    def _copy(
        self,
        shape: Tuple[int, ...] = None,
        strides: Tuple[int, ...] = None,
        offset: int = None,
        scalar_offset: nl.ndarray = None,
        vector_offset: nl.ndarray = None,
        indirect_dim: Optional[int] = None,
        dtype: object = None,
        base_tensor: nl.ndarray = None,
    ) -> "TensorView":
        view = TensorView(base_tensor if base_tensor is not None else self.base_tensor)
        view.shape = tuple(shape) if shape is not None else self.shape
        view.strides = tuple(strides) if strides is not None else self.strides
        view.offset = offset if offset is not None else self.offset
        view.scalar_offset = (
            scalar_offset if scalar_offset is not None else self.scalar_offset
        )
        view.vector_offset = (
            vector_offset if vector_offset is not None else self.vector_offset
        )
        view.indirect_dim = (
            indirect_dim if indirect_dim is not None else self.indirect_dim
        )
        view.dtype = dtype if dtype is not None else self.dtype

        for i in range(len(view.strides)):
            kernel_assert(
                view.strides[i] >= 0,
                f"Stride at dimension {i} must be non-negative, got {view.strides[i]}",
            )

        kernel_assert(len(view.shape) == len(view.strides), "Dimension count mismatch")
        kernel_assert(view.offset >= 0, "Offset must be non-negative")

        kernel_assert(
            view.scalar_offset is None or view.vector_offset is None,
            "Cannot combine scalar_offset and vector_offset",
        )
        return view

    def _get_pattern_and_offset(self):
        ap_pattern = []
        for i in range(self.get_dim()):
            ap_pattern.append((self.strides[i], self.shape[i]))
        return ap_pattern, self.offset

    def get_view(self) -> nl.ndarray:
        kernel_assert(
            len(self.shape) == len(self.strides), "len(self.shape) == len(self.strides)"
        )

        ap_pattern, offset = self._get_pattern_and_offset()

        if self.indirect_dim != None:
            if self.vector_offset is not None:
                result = self.base_tensor.ap(
                    pattern=ap_pattern,
                    offset=offset,
                    vector_offset=self.vector_offset,
                    indirect_dim=self.indirect_dim,
                    dtype=self.dtype,
                )
            else:
                result = self.base_tensor.ap(
                    pattern=ap_pattern,
                    offset=offset,
                    scalar_offset=self.scalar_offset,
                    indirect_dim=self.indirect_dim,
                    dtype=self.dtype,
                )
        else:
            result = self.base_tensor.ap(
                pattern=ap_pattern, offset=offset, dtype=self.dtype
            )
        return result

    def slice(self, dim: int, start: int, end: int, step: int = 1) -> "TensorView":
        kernel_assert(
            dim < self.get_dim(),
            f"Dimension {dim} out of range for {self.get_dim()}D tensor",
        )
        if self.vector_offset is not None:
            kernel_assert(dim != 0, "Cannot slice vector_select dim (dim 0)")
        kernel_assert(start >= 0, "Start index must be non-negative")
        kernel_assert(end > start, "End index must be greater than start")

        end = min(end, self.shape[dim])

        new_shape = []
        new_strides = []
        for i in range(self.get_dim()):
            if i == dim:

                new_shape.append((end - start + step - 1) // step)

                new_strides.append(self.strides[i] * step)
            else:

                new_shape.append(self.shape[i])
                new_strides.append(self.strides[i])

        new_offset = self.offset + self.strides[dim] * start
        return self._copy(shape=new_shape, strides=new_strides, offset=new_offset)

    @staticmethod
    def validate_permutation(
        permutation: Tuple[int, ...], dim: int, is_sbuf: bool
    ) -> None:
        kernel_assert(
            len(permutation) == dim,
            f"Permutation length {len(permutation)} != dimension count {dim}",
        )
        for i in range(dim):
            kernel_assert(
                permutation[i] < dim,
                f"Permutation index {permutation[i]} >= dimension count {dim}",
            )
            kernel_assert(
                permutation[i] >= 0,
                f"Permutation index {permutation[i]} must be non-negative",
            )

            for j in range(i):
                kernel_assert(
                    permutation[i] != permutation[j],
                    f"Duplicate dimension {permutation[i]} in permutation",
                )
        if is_sbuf:
            kernel_assert(
                permutation[0] == 0, "Partition dimension stay the outermost dimension"
            )

    def permute(self, dims: Tuple[int, ...]) -> "TensorView":
        TensorView.validate_permutation(dims, self.get_dim(), self.is_sbuf())
        if self.vector_offset is not None:
            kernel_assert(
                dims[0] == 0, "Cannot move vector_select dim (dim 0) during permute"
            )

        new_shape = []
        new_strides = []

        for i in range(len(dims)):
            d = dims[i]
            kernel_assert(
                d < self.get_dim(), "Dimension index out of range"
            )                           
            new_shape.append(self.shape[d])
            new_strides.append(self.strides[d])

        return self._copy(shape=new_shape, strides=new_strides)

    def broadcast(self, dim: int, size: int) -> "TensorView":
        kernel_assert(dim < self.get_dim(), f"Dimension {dim} out of range")
        kernel_assert(
            self.shape[dim] == 1,
            f"Can only broadcast size-1 dimensions, got size {self.shape[dim]}",
        )
        if self.vector_offset is not None:
            kernel_assert(dim != 0, "Cannot broadcast vector_select dim (dim 0)")
        if self.is_sbuf():
            kernel_assert(
                dim != 0,
                "Cannot broadcast on partition dimension (dim=0) for SBUF tensors",
            )
        new_shape = []
        new_strides = []
        for i in range(self.get_dim()):
            if i == dim:
                new_shape.append(size)

                new_strides.append(0)
            else:

                new_shape.append(self.shape[i])
                new_strides.append(self.strides[i])

        return self._copy(shape=new_shape, strides=new_strides)

    def _reshape_dim_handle_minus_one(self, dim: int, shape: Tuple[int]) -> Tuple[int]:

        minus_one_index = None
        prod_shape = 1
        for i in range(len(shape)):
            if shape[i] == -1:
                kernel_assert(
                    minus_one_index is None, "Only one dimension can be reshaped to -1"
                )
                minus_one_index = i
            else:
                prod_shape *= shape[i]

        if minus_one_index is None:

            return shape

        kernel_assert(self.shape[dim] % prod_shape == 0, "Cannot reshape with -1")
        new_shape = []
        for i in range(len(shape)):
            if i != minus_one_index:
                new_shape.append(shape[i])
            else:
                new_shape.append(self.shape[dim] // prod_shape)
        return tuple(new_shape)

    def reshape_dim(self, dim: int, shape: Tuple[int, ...]) -> "TensorView":
        kernel_assert(dim < self.get_dim(), f"Dimension {dim} out of range")
        if self.vector_offset is not None:
            kernel_assert(dim != 0, "Cannot reshape vector_select dim (dim 0)")
        if self.is_sbuf():

            kernel_assert(
                (dim > 0) or (len(shape) == 1), "partition dim cannot be reshaped"
            )

        shape = self._reshape_dim_handle_minus_one(dim, shape)

        size_prod = 1
        for i in range(len(shape)):
            size_prod *= shape[i]
        kernel_assert(
            self.shape[dim] == size_prod,
            f"Size mismatch: {self.shape[dim]} != {size_prod}",
        )

        if self.get_dim() > 1:
            new_shape = tuple(
                list(self.shape[:dim]) + list(shape) + list(self.shape[dim + 1 :])
            )
        else:
            new_shape = shape

        reshaped_strides = TensorView.get_trivial_strides(
            shape, base_stride=self.strides[dim]
        )
        new_strides = tuple(
            list(self.strides[:dim])
            + list(reshaped_strides)
            + list(self.strides[dim + 1 :])
        )

        return self._copy(shape=new_shape, strides=new_strides)

    def flatten_dims(self, start_dim: int, end_dim: int) -> "TensorView":
        kernel_assert(
            start_dim < end_dim, "Start dimension must be less than end dimension"
        )
        kernel_assert(
            start_dim < self.get_dim(), f"Start dimension {start_dim} out of range"
        )
        kernel_assert(end_dim < self.get_dim(), f"End dimension {end_dim} out of range")
        if self.vector_offset is not None:
            kernel_assert(start_dim != 0, "Cannot flatten vector_select dim (dim 0)")
        if self.is_sbuf():
            kernel_assert(start_dim > 0, "partition dim cannot be flattened")

        for i in range(start_dim, end_dim):
            kernel_assert(
                self.strides[i] == self.shape[i + 1] * self.strides[i + 1],
                f"Dimensions {i} and {i + 1} are not contiguous in memory",
            )

        flattened_size = 1
        for i in range(start_dim, end_dim + 1):
            flattened_size *= self.shape[i]

        new_shape = tuple(
            list(self.shape[:start_dim])
            + [flattened_size]
            + list(self.shape[end_dim + 1 :])
        )
        new_strides = tuple(
            list(self.strides[:start_dim])
            + [self.strides[end_dim]]
            + list(self.strides[end_dim + 1 :])
        )

        return self._copy(shape=new_shape, strides=new_strides)

    def expand_dim(self, dim: int) -> "TensorView":
        kernel_assert(dim <= self.get_dim(), f"Dimension {dim} out of range")
        if self.vector_offset is not None:
            kernel_assert(dim != 0, "Cannot expand before vector_select dim (dim 0)")
        if self.is_sbuf():
            kernel_assert(dim > 0, "partition dim cannot be expanded")

        if dim == self.get_dim():
            new_stride = 1
        else:
            new_stride = self.strides[dim] * self.shape[dim]
        new_shape = tuple(list(self.shape[:dim]) + [1] + list(self.shape[dim:]))
        new_strides = tuple(
            list(self.strides[:dim]) + [new_stride] + list(self.strides[dim:])
        )

        return self._copy(shape=new_shape, strides=new_strides)

    def squeeze_dim(self, dim: int) -> "TensorView":
        kernel_assert(dim < self.get_dim(), f"Dimension {dim} out of range")
        kernel_assert(
            self.shape[dim] == 1,
            f"Can only squeeze size-1 dimensions, got size {self.shape[dim]}",
        )
        if self.vector_offset is not None:
            kernel_assert(dim != 0, "Cannot squeeze vector_select dim (dim 0)")
        if self.is_sbuf():
            kernel_assert(dim > 0, "partition dim cannot be squeezed")

        new_shape = tuple(list(self.shape[:dim]) + list(self.shape[dim + 1 :]))
        new_strides = tuple(list(self.strides[:dim]) + list(self.strides[dim + 1 :]))

        return self._copy(shape=new_shape, strides=new_strides)

    def _dynamic_select(self, dim: int, index: nl.ndarray) -> "TensorView":
        kernel_assert(self.indirect_dim is None, "Cannot have multiple dynamic selects")
        kernel_assert(
            self.strides[dim] != 0,
            "Cannot dynamic select on broadcast dimension (stride=0)",
        )

        view_stride = self.strides[dim]
        base_tensor, base_dim = self._find_or_create_base_dim_for_stride(view_stride)

        new_shape = self.shape[:dim] + self.shape[dim + 1 :]
        new_strides = self.strides[:dim] + self.strides[dim + 1 :]

        return self._copy(
            shape=new_shape,
            strides=new_strides,
            scalar_offset=index,
            indirect_dim=base_dim,
            base_tensor=base_tensor,
        )

    def vector_select(self, dim: int, vector_offset: nl.ndarray) -> "TensorView":
        kernel_assert(dim == 0, "vector_select currently only supports dim=0")
        kernel_assert(self.indirect_dim is None, "Cannot have multiple dynamic selects")
        kernel_assert(
            self.scalar_offset is None,
            "Cannot combine vector_select with scalar_offset",
        )
        kernel_assert(
            self.strides[dim] != 0,
            "Cannot vector_select on broadcast dimension (stride=0)",
        )
        for i in range(len(self.strides)):
            kernel_assert(
                self.strides[dim] >= self.strides[i],
                "vector_select dim must have the largest stride (no permute before vector_select)",
            )

        view_stride = self.strides[dim]
        base_tensor, base_dim = self._find_or_create_base_dim_for_stride(view_stride)

        p_count = vector_offset.shape[0]
        new_shape = (p_count,) + self.shape[1:]

        return self._copy(
            shape=new_shape,
            vector_offset=vector_offset,
            indirect_dim=base_dim,
            base_tensor=base_tensor,
        )

    def _find_or_create_base_dim_for_stride(self, view_stride: int):
        base_shape = list(self.base_tensor.shape)
        base_strides = TensorView.get_trivial_strides(self.base_tensor.shape)
        ndim = len(base_strides)

        min_reshape_dim = 0 if self.is_hbm() else 1

        for i in range(ndim - 1, -1, -1):
            if base_strides[i] == view_stride:
                return self.base_tensor, i

        for i in range(ndim - 1, min_reshape_dim - 1, -1):
            if view_stride % base_strides[i] == 0:
                split_factor = view_stride // base_strides[i]
                can_split = (
                    base_shape[i] >= split_factor and base_shape[i] % split_factor == 0
                )
                if can_split:
                    outer_size = base_shape[i] // split_factor
                    new_base_shape = tuple(
                        base_shape[:i]
                        + [outer_size, split_factor]
                        + base_shape[i + 1 :]
                    )
                    return self.base_tensor.reshape(new_base_shape), i

        kernel_assert(False, f"Cannot create base dim with stride {view_stride}")

    def select(self, dim: int, index: Union[int, nl.ndarray]) -> "TensorView":
        if not isinstance(index, int):
            return self._dynamic_select(dim, index)

        new_view = self.slice(dim, index, index + 1)
        return new_view.squeeze_dim(dim)

    @staticmethod
    def key_in_dict(key, dicti):
        for k in dicti.keys():
            if k == key:
                return True
        return False

    @staticmethod
    def _rearrange_detect_src_reshapes(
        src_pattern: Tuple[Union[str, Tuple[str]]], fixed_sizes: Dict[str, int]
    ) -> List[Dict]:
        src_reshapes = []
        dim_offset = 0
        for i in range(len(src_pattern)):
            if isinstance(src_pattern[i], tuple):
                shape = []
                for j in range(len(src_pattern[i])):
                    if TensorView.key_in_dict(src_pattern[i][j], fixed_sizes):
                        shape.append(fixed_sizes[src_pattern[i][j]])
                    else:
                        shape.append(-1)
                src_reshapes.append({"dim": i + dim_offset, "shape": tuple(shape)})
                dim_offset += len(shape) - 1
        return src_reshapes

    @staticmethod
    def _rearrange_detect_dst_flattens(
        dst_pattern: Tuple[Union[str, Tuple[str]]],
    ) -> List[Dict]:
        dst_flattens = []
        dim_offset = 0
        for i in range(len(dst_pattern)):
            if isinstance(dst_pattern[i], tuple):
                dst_flattens.append(
                    {
                        "start_dim": i + dim_offset,
                        "end_dim": i + dim_offset + len(dst_pattern[i]) - 1,
                    }
                )
                dim_offset += len(dst_pattern[i]) - 1
        return dst_flattens

    @staticmethod
    def _rearrange_expand_pattern(pattern: Tuple[Union[str, Tuple[str]]]) -> Tuple[str]:
        ret = []
        for i in range(len(pattern)):
            if isinstance(pattern[i], tuple):
                for j in range(len(pattern[i])):
                    ret.append(pattern[i][j])
            else:
                ret.append(pattern[i])
        return tuple(ret)

    @staticmethod
    def _rearrange_get_permutation(
        src_pattern: Tuple[str], dst_pattern: Tuple[str]
    ) -> Tuple[int, ...]:
        permutation = []
        for i in range(len(dst_pattern)):
            for j in range(len(src_pattern)):
                if src_pattern[j] == dst_pattern[i]:
                    permutation.append(j)
                    break
        return tuple(permutation)

    def rearrange(
        self,
        src_pattern: Tuple[Union[str, Tuple[str]]],
        dst_pattern: Tuple[Union[str, Tuple[str]]],
        fixed_sizes: Dict[str, int] = None,
    ) -> "TensorView":
        fixed_sizes = {} if fixed_sizes is None else fixed_sizes
        src_reshapes = TensorView._rearrange_detect_src_reshapes(
            src_pattern, fixed_sizes
        )
        src_ordering = TensorView._rearrange_expand_pattern(src_pattern)
        dst_flattens = TensorView._rearrange_detect_dst_flattens(dst_pattern)
        dst_ordering = TensorView._rearrange_expand_pattern(dst_pattern)
        permutation = TensorView._rearrange_get_permutation(src_ordering, dst_ordering)

        t = self._copy()
        for reshape in src_reshapes:
            t = t.reshape_dim(reshape["dim"], reshape["shape"])
        t = t.permute(permutation)
        for flatten in dst_flattens:
            t = t.flatten_dims(flatten["start_dim"], flatten["end_dim"])
        return t

    @staticmethod
    def _reshape_validate(current_shape, current_strides, new_shape, is_hbm):
        current_numel = num_elts(current_shape)
        new_numel = num_elts(new_shape)
        kernel_assert(
            current_numel == new_numel,
            f"reshape: size mismatch {current_shape} ({current_numel} elements) -> {new_shape} ({new_numel} elements)",
        )
        if not is_hbm and len(current_shape) > 0:
            kernel_assert(
                len(new_shape) > 0 and new_shape[0] == current_shape[0],
                f"reshape: partition dim (dim 0) size must be preserved for non-HBM tensors, "
                f"got {current_shape[0]} -> {new_shape[0] if len(new_shape) > 0 else '(empty)'}",
            )

    @staticmethod
    def _reshape_remove_unit_dims(current_shape, current_strides, is_hbm):
        start = 0 if is_hbm else 1
        filtered_shape = list(current_shape[:start])
        filtered_strides = list(current_strides[:start])
        for k in range(start, len(current_shape)):
            if current_shape[k] != 1:
                filtered_shape.append(current_shape[k])
                filtered_strides.append(current_strides[k])
        return filtered_shape, filtered_strides

    @staticmethod
    def _reshape_collapse_contiguous_blocks(filtered_shape, filtered_strides, is_hbm):
        blocks = []
        i = 0
        if not is_hbm and len(filtered_shape) > 0:
            blocks.append((filtered_shape[0], filtered_strides[0]))
            i = 1
        while i < len(filtered_shape):
            kernel_assert(
                filtered_shape[i] > 0, f"reshape: zero-size dimension at index {i}"
            )
            size = filtered_shape[i]
            j = i
            while (
                j + 1 < len(filtered_shape)
                and filtered_strides[j]
                == filtered_strides[j + 1] * filtered_shape[j + 1]
            ):
                j += 1
                size *= filtered_shape[j]
            blocks.append((size, filtered_strides[j]))
            i = j + 1
        if not blocks:
            blocks.append((1, 1))
        return blocks

    @staticmethod
    def _reshape_repartition_blocks(blocks, current_shape, current_strides, new_shape):
        new_strides = [0] * len(new_shape)
        b = len(blocks) - 1
        block_size, base_stride = blocks[b]
        stride = base_stride

        for idx in range(len(new_shape) - 1, -1, -1):
            d = new_shape[idx]
            kernel_assert(
                d <= block_size and block_size % d == 0,
                f"reshape: non-contiguous layout prevents reshape without copy. "
                f"shape: {current_shape}, strides: {current_strides} -> {new_shape}",
            )
            new_strides[idx] = stride
            stride *= d
            block_size //= d
            if block_size == 1 and b > 0:
                b -= 1
                block_size, base_stride = blocks[b]
                stride = base_stride

        return tuple(new_strides)

    def reshape(self, new_shape: Tuple[int, ...]) -> "TensorView":
        is_hbm = self.is_hbm()
        TensorView._reshape_validate(self.shape, self.strides, new_shape, is_hbm)

        filtered_shape, filtered_strides = TensorView._reshape_remove_unit_dims(
            self.shape, self.strides, is_hbm
        )
        blocks = TensorView._reshape_collapse_contiguous_blocks(
            filtered_shape, filtered_strides, is_hbm
        )
        new_strides = TensorView._reshape_repartition_blocks(
            blocks, self.shape, self.strides, new_shape
        )
        return self._copy(shape=new_shape, strides=new_strides)

    def has_dynamic_access(self) -> bool:
        return self.scalar_offset != None and self.indirect_dim != None

from typing import Optional, Tuple, Union

import nki.isa as nisa

SHARDING_THRESHOLD = 18

_DGE_MODE_NONE = 3

BxS_FULL_TILE_SIZE = 512

def validate_shapes(
    input_view: TensorView,
    gamma_view: TensorView,
    output_view: TensorView,
) -> Tuple[int, int, int, int]:
    H0 = nl.tile_size.pmax
    if input_view.is_sbuf():
        _H0, BxS, H1 = input_view.shape
        kernel_assert(
            _H0 == H0,
            f"Input tensor in SBUF does not have partition dimension H0 of {H0}, got {_H0}",
        )
        H = _H0 * H1
    else:
        B, S, H = input_view.shape
        BxS = B * S
        kernel_assert(
            H % H0 == 0, f"Input tensor H dimension must be divisible by {H0}, got {H}"
        )
        H1 = H // H0

    kernel_assert(
        output_view.shape == (H0, BxS, H1),
        f"Output shape expected is (H0, BxS, H1): {(H0, BxS, H1)}, got {output_view.shape}",
    )

    kernel_assert(
        gamma_view.shape == (1, H),
        f"Malformed shape of gamma expected (1, {H}), got {gamma_view.shape}",
    )
    return BxS, H, H0, H1

def load_input_to_sbuf(
    input_hbm: TensorView,
    input_sb: TensorView,
    num_H_shards: int,
    hidden_dim_tp: bool = False,
) -> TensorView:
    H0 = nl.tile_size.pmax
    BxS, H = input_hbm.shape
    H1 = H // H0
    H2 = H1 // num_H_shards

    if hidden_dim_tp:

        input_hbm_view = (
            input_hbm.reshape_dim(dim=1, shape=[H1, H0])
            .flatten_dims(start_dim=0, end_dim=1)
            .expand_dim(dim=1)
            .expand_dim(dim=1)
        )
        input_sb_view = (
            input_sb.flatten_dims(start_dim=1, end_dim=2)
            .expand_dim(dim=1)
            .expand_dim(dim=1)
        )
        nisa.dma_transpose(dst=input_sb_view.get_view(), src=input_hbm_view.get_view())
    else:

        input_hbm_view = input_hbm.reshape_dim(
            dim=1, shape=[num_H_shards, H0, H2]
        ).permute(dims=[2, 0, 1, 3])
        input_sb_view = input_sb.reshape_dim(dim=2, shape=[num_H_shards, H2])
        nisa.dma_copy(
            dst=input_sb_view.get_view(),
            src=input_hbm_view.get_view(),
            dge_mode=_DGE_MODE_NONE,
        )
    return input_sb

def load_gamma_to_sbuf(
    gamma_hbm: TensorView,
    gamma_sb: TensorView,
    num_H_shards: int,
    hidden_dim_tp: bool = False,
) -> TensorView:
    H0 = nl.tile_size.pmax
    H = gamma_hbm.shape[1]
    H1 = H // H0
    H2 = H1 // num_H_shards

    gamma_hbm = gamma_hbm.flatten_dims(start_dim=0, end_dim=1)
    if hidden_dim_tp:

        gamma_hbm_view = (
            gamma_hbm.reshape_dim(dim=0, shape=[H1, H0])
            .expand_dim(dim=1)
            .expand_dim(dim=1)
        )
        gamma_sb_dst_view = gamma_sb.expand_dim(dim=1).expand_dim(dim=1)
        nisa.dma_transpose(
            dst=gamma_sb_dst_view.get_view(), src=gamma_hbm_view.get_view()
        )
    else:

        gamma_hbm_view = gamma_hbm.reshape_dim(
            dim=0, shape=[num_H_shards, H0, H2]
        ).permute(dims=[1, 0, 2])
        gamma_sb_view_reshaped = gamma_sb.reshape_dim(dim=1, shape=[num_H_shards, H2])
        nisa.dma_copy(
            dst=gamma_sb_view_reshaped.get_view(),
            src=gamma_hbm_view.get_view(),
            dge_mode=_DGE_MODE_NONE,
        )
    return gamma_sb

def rmsnorm_tkg(
    input: Union[TensorView, nl.ndarray],
    gamma: Union[TensorView, nl.ndarray],
    output: Union[TensorView, nl.ndarray],
    eps: float = 1e-6,
    hidden_actual: Optional[int] = None,
    hidden_dim_tp: bool = False,
    no_h_interleave: bool = False,
    output_num_h_shards: Optional[int] = None,
    use_heap_memory: bool = False,
    sbm: Optional[SbufManager] = None,
    name_prefix: str = "",
):

    input_view = TensorView(input) if not isinstance(input, TensorView) else input
    gamma_view = TensorView(gamma) if not isinstance(gamma, TensorView) else gamma
    output_view = TensorView(output) if not isinstance(output, TensorView) else output

    BxS, H, H0, H1 = validate_shapes(input_view, gamma_view, output_view)

    if not hidden_actual:
        hidden_actual = H

    if not sbm:

        max_tile_size = min(BxS, BxS_FULL_TILE_SIZE)
        sbuf_size = (
            BxS * H1                       
            + H1         
            + 1       
            + H0                
            + 2 * max_tile_size * H1                               
            + max_tile_size                          
        ) * 4                        
        use_auto_alloc = True
        sbm = SbufManager(
            sb_lower_bound=0,
            sb_upper_bound=min(sbuf_size, nl.tile_size.total_available_sbuf_size),
            logger=Logger("rmsnorm_tkg"),
            use_auto_alloc=use_auto_alloc,
        )

    if output_view.is_sbuf():
        output_sb_view = output_view
    else:
        alloc_tensor = sbm.alloc_heap if use_heap_memory else sbm.alloc_stack
        output_sb = alloc_tensor(
            (H0, BxS, H1),
            dtype=input_view.dtype,
            buffer=nl.sbuf,
            name=f"{name_prefix}rmsnorm_output_sb",
        )
        output_sb_view = TensorView(output_sb)

    _, lnc, shard_id = get_verified_program_sharding_info("rmsnorm_tkg", (0, 1))

    num_shards = lnc
    do_shard = num_shards == 2 and BxS > SHARDING_THRESHOLD and BxS % lnc == 0
    if not do_shard:
        num_shards, shard_id = 1, 0

    num_H_shards_in_output_H_dim = 1 if (hidden_dim_tp or no_h_interleave) else lnc
    if output_num_h_shards is not None and not no_h_interleave:
        num_H_shards_in_output_H_dim = output_num_h_shards

    shard_size = BxS // num_shards

    if not input_view.is_sbuf():
        input_view_flat = input_view.flatten_dims(start_dim=0, end_dim=1)
        input_view_sharded = input_view_flat.slice(
            dim=0, start=shard_id * shard_size, end=(shard_id + 1) * shard_size
        )
    else:
        input_view_sharded = input_view.slice(
            dim=1, start=shard_id * shard_size, end=(shard_id + 1) * shard_size
        )

    output_view_sharded = output_sb_view.slice(
        dim=1, start=shard_id * shard_size, end=(shard_id + 1) * shard_size
    )

    rmsnorm_tkg_llama_impl(
        input=input_view_sharded,
        gamma=gamma_view,
        output=output_view_sharded,
        num_H_shards=num_H_shards_in_output_H_dim,
        hidden_actual=hidden_actual,
        eps=eps,
        hidden_dim_tp=hidden_dim_tp,
        use_heap_memory=use_heap_memory,
        sbm=sbm,
        name_prefix=name_prefix,
    )

    if output_view.is_sbuf():
        if do_shard:
            output_view_sharded_other_core = output_sb_view.slice(
                dim=1,
                start=(1 - shard_id) * shard_size,
                end=(2 - shard_id) * shard_size,
            )
            nisa.sendrecv(
                dst=output_view_sharded_other_core.get_view(),
                src=output_view_sharded.get_view(),
                send_to_rank=1 - shard_id,
                recv_from_rank=1 - shard_id,
                pipe_id=0,
            )

        if isinstance(output, TensorView):
            return output_sb_view.reshape((H0, BxS, H1))
        else:
            return output.reshape((H0, BxS, H1))

    output_hbm_view_sharded = output_view.slice(
        dim=1, start=shard_id * shard_size, end=(shard_id + 1) * shard_size
    )

    nisa.dma_copy(
        dst=output_hbm_view_sharded.get_view(), src=output_view_sharded.get_view()
    )

    if use_heap_memory:
        sbm.pop_heap()

    return output

def process_rmsnorm_tile(
    input_sb_view: TensorView,
    gamma_sb_view: TensorView,
    output_sb_view: TensorView,
    eps_view: TensorView,
    matmul_reduction_const_view: TensorView,
    bxs_tile: Tuple,
    hidden_actual: int,
    use_heap_memory: bool = False,
    sbm: SbufManager = None,
    name_prefix: str = "",
):
    alloc_tensor = sbm.alloc_heap if use_heap_memory else sbm.alloc_stack

    num_allocated_tensor = 0
    inter_dtype = nl.float32

    kernel_assert(
        input_sb_view.shape == output_sb_view.shape,
        "Input and output tensor shapes must match for RMSNorm processing",
    )
    H0, BxS, H1 = input_sb_view.shape

    input_fp32 = alloc_tensor(
        shape=(H0, BxS, H1),
        dtype=inter_dtype,
        buffer=nl.sbuf,
        name=f"{name_prefix}rmsnorm_input_fp32_{bxs_tile.index}",
    )
    num_allocated_tensor += 1
    nisa.tensor_copy(dst=input_fp32[...], src=input_sb_view.get_view())

    rmsnorm_square = alloc_tensor(
        shape=(H0, BxS, H1),
        dtype=inter_dtype,
        buffer=nl.sbuf,
        name=f"{name_prefix}rmsnorm_square_{bxs_tile.index}",
    )
    num_allocated_tensor += 1
    nisa.activation(rmsnorm_square[...], op=nl.square, data=input_fp32[...])

    rmsnorm_reduced_square = alloc_tensor(
        shape=(H0, BxS),
        dtype=inter_dtype,
        buffer=nl.sbuf,
        name=f"{name_prefix}rmsnorm_reduced_square_{bxs_tile.index}",
    )
    num_allocated_tensor += 1
    nisa.tensor_reduce(rmsnorm_reduced_square[...], nl.add, rmsnorm_square[...], axis=2)

    gamma_mult = alloc_tensor(
        shape=(H0, BxS, H1),
        dtype=inter_dtype,
        buffer=nl.sbuf,
        name=f"{name_prefix}rmsnorm_gamma_mult_{bxs_tile.index}",
    )
    num_allocated_tensor += 1
    gamma_mult_view = TensorView(gamma_mult)
    nisa.tensor_tensor(
        gamma_mult_view.get_view(),
        input_fp32[...],
        gamma_sb_view.get_view(),
        nl.multiply,
    )

    if sbm.is_auto_alloc():
        final_reduced = nl.ndarray((H0, BxS), dtype=nl.float32, buffer=nl.psum)
    else:
        final_reduced = nl.ndarray(
            (H0, BxS), dtype=nl.float32, buffer=nl.psum, address=(0, 0)
        )
    nisa.nc_matmul(
        stationary=matmul_reduction_const_view.get_view(),
        moving=rmsnorm_reduced_square,
        dst=final_reduced,
    )

    hidden_scale = 1.0 / hidden_actual
    nisa.activation(
        rmsnorm_reduced_square[...],
        op=nl.rsqrt,
        data=final_reduced[...],
        scale=hidden_scale,
        bias=eps_view.get_view(),
    )

    reduced_view = (
        TensorView(rmsnorm_reduced_square).expand_dim(dim=2).broadcast(dim=2, size=H1)
    )
    nisa.tensor_tensor(
        output_sb_view.get_view(),
        gamma_mult_view.get_view(),
        reduced_view.get_view(),
        nl.multiply,
    )

    if use_heap_memory:
        for _ in range(num_allocated_tensor):
            sbm.pop_heap()

def rmsnorm_tkg_llama_impl(
    input: TensorView,
    gamma: TensorView,
    output: TensorView,
    num_H_shards: int,
    hidden_actual: Optional[int],
    eps: float,
    hidden_dim_tp: bool = False,
    use_heap_memory: bool = False,
    sbm: SbufManager = None,
    name_prefix: str = "",
):

    if input.is_sbuf():
        H0, BxS, H1 = input.shape
        H = H0 * H1
    else:
        BxS, H = input.shape
        H0 = nl.tile_size.pmax
        H1 = H // H0

    if hidden_dim_tp:
        kernel_assert(
            num_H_shards == 1, "When hidden_dim_tp is True, num_H_shards must be 1"
        )

    inter_dtype = nl.float32

    alloc_tensor = sbm.alloc_heap if use_heap_memory else sbm.alloc_stack

    num_allocated_tensor = 0

    if input.is_sbuf():
        input_sb_view = input
    else:
        input_sb_view = load_input_to_sbuf(
            input_hbm=input,
            input_sb=output,
            num_H_shards=num_H_shards,
            hidden_dim_tp=hidden_dim_tp,
        )

    gamma_align = 32 if hidden_dim_tp else None
    gamma_sb = alloc_tensor(
        shape=(H0, H1),
        dtype=gamma.dtype,
        name=f"{name_prefix}rmsnorm_gamma",
        align=gamma_align,
    )
    num_allocated_tensor += 1
    gamma_sb_view = load_gamma_to_sbuf(
        gamma_hbm=gamma,
        gamma_sb=TensorView(gamma_sb),
        num_H_shards=num_H_shards,
        hidden_dim_tp=hidden_dim_tp,
    )

    eps_sb = alloc_tensor(
        shape=(H0, 1),
        dtype=inter_dtype,
        buffer=nl.sbuf,
        name=f"{name_prefix}rmsnorm_eps",
    )
    num_allocated_tensor += 1
    nisa.memset(eps_sb, value=eps)

    matmul_reduction_const = alloc_tensor(
        shape=(H0, H0),
        dtype=inter_dtype,
        buffer=nl.sbuf,
        name=f"{name_prefix}rmsnorm_mm_reduced_const",
    )
    num_allocated_tensor += 1
    nisa.memset(matmul_reduction_const, value=1.0)

    for bxs_tile in TiledRange(BxS, BxS_FULL_TILE_SIZE):
        input_sb_view_tile = input_sb_view.slice(
            dim=1,
            start=bxs_tile.start_offset,
            end=bxs_tile.start_offset + bxs_tile.size,
        )
        gamma_sb_view_tile = gamma_sb_view.expand_dim(dim=1).broadcast(
            dim=1, size=bxs_tile.size
        )
        output_sb_view_tile = output.slice(
            dim=1,
            start=bxs_tile.start_offset,
            end=bxs_tile.start_offset + bxs_tile.size,
        )
        process_rmsnorm_tile(
            input_sb_view=input_sb_view_tile,
            gamma_sb_view=gamma_sb_view_tile,
            output_sb_view=output_sb_view_tile,
            eps_view=TensorView(eps_sb),
            matmul_reduction_const_view=TensorView(matmul_reduction_const),
            bxs_tile=bxs_tile,
            hidden_actual=hidden_actual,
            use_heap_memory=use_heap_memory,
            sbm=sbm,
            name_prefix=name_prefix,
        )

    if use_heap_memory:
        for _ in range(num_allocated_tensor):
            sbm.pop_heap()

tensor_view = _self_module

P_MAX = 128
PE_COLUMN_TILE_32 = 32                                         
PE_COLUMN_TILE_64 = 64                                              
PE_COLUMN_TILE_128 = 128                                                           

XHBMLayout_H_T__0 = 0
XHBMLayout_T_H__1 = 1

XSBLayout_tp102__0 = 0
XSBLayout_tp2013__1 = 1
XSBLayout_tp201__2 = 2
XSBLayout__128_Hdiv128_T__3 = 3

def router_topk_input_w_load(w: nl.ndarray, x_sb_layout, name=""):
    H, E = w.shape
    num_h_tiles = H // P_MAX
    num_h_tiles_by_2 = num_h_tiles // 2

    w_sb = None

    if x_sb_layout not in [0, 1, 2, 3]:
        kernel_assert(
            False,
            f"router_topk_input_w_load only x_sb_layout=0,1,2,3 are supported. Specified layout value: {x_sb_layout}",
        )

    if x_sb_layout == XSBLayout_tp102__0:

        w_reshape = w.reshape((P_MAX, num_h_tiles, E))
        w_sb = nl.ndarray(
            (P_MAX, num_h_tiles, E), dtype=w.dtype, buffer=nl.sbuf, name=name
        )
        nisa.dma_copy(src=w_reshape, dst=w_sb)

    elif x_sb_layout == XSBLayout_tp2013__1:

        w_reshape = w.reshape((2, P_MAX, num_h_tiles_by_2, E))
        w_sb = nl.ndarray(
            (P_MAX, 2, num_h_tiles_by_2, E), dtype=w.dtype, buffer=nl.sbuf, name=name
        )
        nisa.dma_copy(
            src=tensor_view.TensorView(w_reshape).permute([1, 0, 2, 3]).get_view(),
            dst=tensor_view.TensorView(w_sb).get_view(),
        )

        w_sb = w_sb.reshape((P_MAX, num_h_tiles, E))

    else:                     

        w_sb = nl.ndarray(
            (P_MAX, num_h_tiles, E), dtype=w.dtype, buffer=nl.sbuf, name=name
        )

        nisa.dma_copy(
            src=w.ap(pattern=[[E, 128], [128 * E, num_h_tiles], [1, E]], offset=0),
            dst=tensor_view.TensorView(w_sb).get_view(),
        )

    return w_sb

def router_topk_decode(
    x: nl.ndarray,
    w: nl.ndarray,
    w_bias: nl.ndarray,
    act_fn,
    k: int,
    norm_topk_prob: bool = False,
    x_sb_layout: int = XSBLayout_tp2013__1,
):

    H, E = w.shape
    _, T, H_free = x.shape                   

    kernel_assert(T <= P_MAX, f"router_topk_decode requires T <= {P_MAX}, got {T}")
    kernel_assert(H % P_MAX == 0, f"H ({H}) must be a multiple of {P_MAX}")
    kernel_assert(k <= 8, f"K ({k}) must be <= 8")
    kernel_assert(x.dtype == nl.bfloat16, f"x dtype ({x.dtype}) must be bfloat16")
    kernel_assert(w.dtype == nl.bfloat16, f"w dtype ({w.dtype}) must be bfloat16")
    num_h_tiles = H // P_MAX
    has_bias = w_bias is not None

    w_sb = router_topk_input_w_load(
        w, x_sb_layout=x_sb_layout, name="router_decode_w_sb"
    )

    router_logits_bias_broadcasted_sb = None
    if has_bias:
        assert False

    if T <= PE_COLUMN_TILE_32:
        pe_array_column_tiling_size = PE_COLUMN_TILE_32
    elif T <= PE_COLUMN_TILE_64:
        pe_array_column_tiling_size = PE_COLUMN_TILE_64
    else:
        pe_array_column_tiling_size = PE_COLUMN_TILE_128

    num_pe_array_column_tiles = PE_COLUMN_TILE_128 // pe_array_column_tiling_size
    tile_size = (P_MAX, pe_array_column_tiling_size)

    router_logits_psum = nl.ndarray((P_MAX, E), nl.float32, buffer=nl.psum)
    nisa.memset(dst=router_logits_psum, value=0)
    for h_tile_idx in range(num_h_tiles):
        w_tile_sb = w_sb[:, h_tile_idx, :]
        x_tile_sb = x.ap(
            pattern=[[T * num_h_tiles, P_MAX], [num_h_tiles, T]],
            offset=h_tile_idx,
        )

        current_column_tile_index = h_tile_idx % num_pe_array_column_tiles
        current_column_tile_column_offset = (
            current_column_tile_index * pe_array_column_tiling_size
        )
        tile_position = (0, current_column_tile_column_offset)

        nisa.nc_matmul(
            dst=router_logits_psum[nl.ds(current_column_tile_column_offset, T), :],
            stationary=x_tile_sb,
            moving=w_tile_sb,
            tile_position=tile_position,
            tile_size=tile_size,
        )

    router_logits_sb1 = nl.ndarray((T, 1, E), dtype=nl.float32, buffer=nl.sbuf)
    if has_bias:
        nisa.tensor_tensor(
            dst=router_logits_sb1[:T, 0, :],
            data1=router_logits_psum[:T, :E],
            data2=router_logits_bias_broadcasted_sb[:T, :E],
            op=nl.add,
        )
    else:
        nisa.tensor_copy(
            dst=router_logits_sb1[:T, 0, :],
            src=router_logits_psum[:T, :E],
        )

    for column_tile_idx in range(1, num_pe_array_column_tiles):
        current_column_tile_column_offset = (
            column_tile_idx * pe_array_column_tiling_size
        )
        nisa.tensor_tensor(
            dst=router_logits_sb1[:T, 0, :],
            data1=router_logits_sb1[:T, 0, :],
            data2=router_logits_psum[nl.ds(current_column_tile_column_offset, T), :],
            op=nl.add,
        )

    router_logits_sb = router_logits_sb1

    router_logits_2d = router_logits_sb.reshape((T, E))

    expert_affinities_full_2d = nl.ndarray((T, E), dtype=nl.float32, buffer=nl.sbuf)
    negmax_sb = nl.ndarray((T, 1), dtype=nl.float32, buffer=nl.sbuf)
    nisa.tensor_reduce(
        dst=negmax_sb,
        op=nl.maximum,
        data=router_logits_2d,
        axis=1,
        negate=True,
        keepdims=True,
    )
    exp_sum_sb = nl.ndarray((T, 1), dtype=nl.float32, buffer=nl.sbuf)
    result_exp = nl.ndarray((T, E), dtype=nl.float32, buffer=nl.sbuf)
    nisa.activation(
        dst=result_exp,
        op=nl.exp,
        data=router_logits_2d,
        bias=negmax_sb,
        reduce_op=nl.add,
        reduce_res=exp_sum_sb,
        reduce_cmd=nisa.reduce_cmd.reset_reduce,
    )
    nisa.reciprocal(dst=exp_sum_sb, data=exp_sum_sb)
    nisa.tensor_scalar(
        dst=expert_affinities_full_2d,
        data=result_exp,
        op0=nl.multiply,
        operand0=exp_sum_sb,
    )

    expert_affinities_full_sb = expert_affinities_full_2d.reshape((T, 1, E))

    topk_input_sb = expert_affinities_full_sb

    router_logits_topk_sb = nl.ndarray((T, 1, k), dtype=nl.float32, buffer=nl.sbuf)
    router_indexes_topk_sb = nl.ndarray((T, 1, k), dtype=nl.uint32, buffer=nl.sbuf)

    router_logits_top8_sb = nl.ndarray((T, 8), dtype=nl.float32, buffer=nl.sbuf)
    nisa.max8(
        dst=router_logits_top8_sb[:T, :],
        src=topk_input_sb[:T, 0, :],
    )
    nisa.tensor_copy(
        dst=router_logits_topk_sb[:T, 0, :],
        src=router_logits_top8_sb[:T, :k],
    )

    tmp_buffer = nl.ndarray((T, 8), dtype=nl.uint32, buffer=nl.sbuf)
    nisa.nc_find_index8(
        dst=tmp_buffer[:T, :],
        data=topk_input_sb[:T, 0, :],
        vals=router_logits_top8_sb,
    )
    nisa.tensor_copy(
        dst=router_indexes_topk_sb[:T, 0, :k],
        src=tmp_buffer[:T, :k],
    )

    expert_affinities_topk_sb = nl.ndarray((T, 1, k), dtype=nl.float32, buffer=nl.sbuf)
    sum_of_max_sb = nl.ndarray((T, 1, 1), dtype=nl.float32, buffer=nl.sbuf)
    nisa.tensor_reduce(
        dst=sum_of_max_sb[:T, 0, :],
        op=nl.add,
        data=router_logits_topk_sb[:T, 0, :],
        axis=1,
        keepdims=True,
    )
    nisa.reciprocal(
        dst=sum_of_max_sb[:T, 0, :],
        data=sum_of_max_sb[:T, 0, :],
    )
    nisa.tensor_scalar(
        dst=expert_affinities_topk_sb[:T, 0, :],
        data=router_logits_topk_sb[:T, 0, :],
        op0=nl.multiply,
        operand0=sum_of_max_sb[:T, 0, :],
    )

    expert_index_out = router_indexes_topk_sb.reshape((T, k))
    expert_affinities_topk_out = expert_affinities_topk_sb.reshape((T, k))

    return expert_index_out, expert_affinities_topk_out

def stream_shuffle_broadcast(src: nl.ndarray, dst: nl.ndarray) -> None:
    dst_npar = dst.shape[0]
    kernel_assert(
        len(src.shape) == 2 and len(dst.shape) == 2, "src and dst must be 2D tensors"
    )
    kernel_assert(
        src.shape[1] == dst.shape[1], "src and dst must have matching final dimension"
    )

    shuffle_mask = [0] * 32
    for i in range((dst_npar + 31) // 32):
        cur_npar = min(32, dst_npar - i * 32)
        nisa.nc_stream_shuffle(
            src=src[0:1, :],
            dst=dst[i * 32 : i * 32 + cur_npar, 0 : dst.shape[1]],
            shuffle_mask=shuffle_mask,
        )

def _selective_fused_gate_up_gemv_t1(
    hidden: nl.ndarray,
    output: nl.ndarray,
    dims: MLPTKGConstantsDimensionSizes,
    sbm: SbufManager,
    gate_up_weight: TensorView,
    warmup: bool = False,
) -> None:
    H0 = dims.H0
    I0 = dims.I0
    T = 1
    H = dims.H_per_shard
    I = dims.I
    num_h_tiles = H // H0
    num_h_tiles_by_2 = num_h_tiles // 2
    num_i_tiles = dims.num_total_128_tiles_per_I
    kernel_assert(
        num_h_tiles % 2 == 0,
        f"tp2013 layout requires an even H/128 tile count, got {num_h_tiles}",
    )
    kernel_assert(
        len(gate_up_weight.shape) == 3
        and gate_up_weight.shape[0] == H
        and gate_up_weight.shape[1] == 2
        and gate_up_weight.shape[2] == I,
        f"fused gate/up weights must have shape [H, 2, I] = [{H}, 2, {I}], got {gate_up_weight.shape}",
    )

    gate_sb = sbm.alloc_stack(
        (dims.I0, dims.num_total_128_tiles_per_I, 1),
        dtype=nl.float32,
        buffer=nl.sbuf,
        name=f"{sbm.get_name_prefix()}gate_gemv",
        align=4,
    )
    gate_silued = sbm.alloc_stack(
        gate_sb.shape,
        dtype=nl.float32,
        buffer=nl.sbuf,
        name=f"{sbm.get_name_prefix()}gate_silued",
    )
    up_sb = sbm.alloc_stack(
        (dims.I0, dims.num_total_128_tiles_per_I, 1),
        dtype=nl.float32,
        buffer=nl.sbuf,
        name=f"{sbm.get_name_prefix()}up_gemv",
        align=4,
    )

    w_fused_5d = sbm.alloc_heap(
        (H0, 2, num_h_tiles_by_2, 2, I),
        dtype=gate_up_weight.dtype,
        buffer=nl.sbuf,
        name=f"{sbm.get_name_prefix()}gate_up_gemv_w_fused",
    )
    fused_weight_view = gate_up_weight.reshape_dim(
        dim=0, shape=(2, H0, num_h_tiles_by_2)
    ).permute(dims=[1, 0, 2, 3, 4])
    if warmup:
        nisa.dma_copy(
            dst=w_fused_5d,
            src=fused_weight_view.get_view(),
            dge_mode=nisa.dge_mode.hwdge,                                                                                                       
            engine=nisa.scalar_engine,                                                                                                    
        )
    else:
        nisa.dma_copy(
            dst=w_fused_5d,
            src=fused_weight_view.get_view(),
            dge_mode=nisa.dge_mode.swdge,
        )
    w_fused = w_fused_5d.reshape((H0, num_h_tiles, 2, I))

    for i_tile in range(num_i_tiles):
        tile_i_start = i_tile * I0
        tile_i_size = min(I0, I - tile_i_start)

        psum_acc = nl.ndarray(
            (I0, T),
            dtype=nl.float32,
            buffer=nl.psum,
            name=f"gate_{sbm.get_name_prefix()}gemv_psum_first_i{i_tile}",
            address=None if sbm.is_auto_alloc() else (0, 0),
        )
        psum_acc_second = nl.ndarray(
            (I0, T),
            dtype=nl.float32,
            buffer=nl.psum,
            name=f"gate_{sbm.get_name_prefix()}gemv_psum_second_i{i_tile}",
            address=None if sbm.is_auto_alloc() else (0, dims._psum_fmax * 4),
        )

        for h_idx in range(num_h_tiles_by_2):
            nisa.nc_matmul(
                dst=psum_acc[0:tile_i_size, 0:T],
                stationary=w_fused[
                    0:H0, h_idx, 0, tile_i_start : tile_i_start + tile_i_size
                ],
                moving=hidden[0:H0, 0:T, h_idx],
            )
        for h_idx in range(num_h_tiles_by_2, num_h_tiles):
            nisa.nc_matmul(
                dst=psum_acc_second[0:tile_i_size, 0:T],
                stationary=w_fused[
                    0:H0, h_idx, 0, tile_i_start : tile_i_start + tile_i_size
                ],
                moving=hidden[0:H0, 0:T, h_idx],
            )

        out_dst = (
            TensorView(gate_sb)
            .slice(dim=0, start=0, end=tile_i_size)
            .slice(dim=1, start=i_tile, end=i_tile + 1)
            .squeeze_dim(dim=1)
            .get_view()
        )
        nisa.tensor_copy(dst=out_dst, src=psum_acc[0:tile_i_size, 0:T])
        psum_acc_second_sb = sbm.alloc_stack(
            (I0, T),
            dtype=nl.float32,
            buffer=nl.sbuf,
            name=f"gate_{sbm.get_name_prefix()}gemv_psum_second_sbuf_i{i_tile}",
            align=4,
        )
        nisa.tensor_copy(
            dst=psum_acc_second_sb[0:tile_i_size, 0:T],
            src=psum_acc_second[0:tile_i_size, 0:T],
        )
        nisa.tensor_tensor(
            dst=out_dst,
            data1=out_dst,
            data2=psum_acc_second_sb[0:tile_i_size, 0:T],
            op=nl.add,
        )

    for i_tile in range(num_i_tiles):
        tile_i_start = i_tile * I0
        tile_i_size = min(I0, I - tile_i_start)

        psum_acc = nl.ndarray(
            (I0, T),
            dtype=nl.float32,
            buffer=nl.psum,
            name=f"up_{sbm.get_name_prefix()}gemv_psum_first_i{i_tile}",
            address=None if sbm.is_auto_alloc() else (0, 0),
        )
        psum_acc_second = nl.ndarray(
            (I0, T),
            dtype=nl.float32,
            buffer=nl.psum,
            name=f"up_{sbm.get_name_prefix()}gemv_psum_second_i{i_tile}",
            address=None if sbm.is_auto_alloc() else (0, dims._psum_fmax * 4),
        )

        for h_idx in range(num_h_tiles_by_2):
            nisa.nc_matmul(
                dst=psum_acc[0:tile_i_size, 0:T],
                stationary=w_fused[
                    0:H0, h_idx, 1, tile_i_start : tile_i_start + tile_i_size
                ],
                moving=hidden[0:H0, 0:T, h_idx],
            )
        for h_idx in range(num_h_tiles_by_2, num_h_tiles):
            nisa.nc_matmul(
                dst=psum_acc_second[0:tile_i_size, 0:T],
                stationary=w_fused[
                    0:H0, h_idx, 1, tile_i_start : tile_i_start + tile_i_size
                ],
                moving=hidden[0:H0, 0:T, h_idx],
            )

        out_dst = (
            TensorView(up_sb)
            .slice(dim=0, start=0, end=tile_i_size)
            .slice(dim=1, start=i_tile, end=i_tile + 1)
            .squeeze_dim(dim=1)
            .get_view()
        )
        nisa.tensor_copy(dst=out_dst, src=psum_acc[0:tile_i_size, 0:T])
        psum_acc_second_sb = sbm.alloc_stack(
            (I0, T),
            dtype=nl.float32,
            buffer=nl.sbuf,
            name=f"up_{sbm.get_name_prefix()}gemv_psum_second_sbuf_i{i_tile}",
            align=4,
        )
        nisa.tensor_copy(
            dst=psum_acc_second_sb[0:tile_i_size, 0:T],
            src=psum_acc_second[0:tile_i_size, 0:T],
        )
        nisa.tensor_tensor(
            dst=out_dst,
            data1=out_dst,
            data2=psum_acc_second_sb[0:tile_i_size, 0:T],
            op=nl.add,
        )

    nisa.activation(
        dst=gate_silued,
        op=nl.silu,
        data=gate_sb,
        scale=1.0,
    )
    nisa.tensor_tensor(dst=output, data1=gate_silued, data2=up_sb, op=nl.multiply)

def _selective_down_gemv_t1(
    hidden: nl.ndarray,
    weight: TensorView,
    output: nl.ndarray,
    dims: MLPTKGConstantsDimensionSizes,
    sbm: SbufManager,
    affinity_scale: nl.ndarray = None,
) -> None:

    H0 = dims.H0       
    I0 = dims.I0       
    T = 1
    I = dims.I

    num_i_tiles = dims.num_total_128_tiles_per_I
    num_h_tiles = dims.H1_shard           
    MAX_PSUM_BANKS = 8
    num_h_batches = (num_h_tiles + MAX_PSUM_BANKS - 1) // MAX_PSUM_BANKS

    w_tiles = []
    for i_tile in range(num_i_tiles):
        tile_i_start = i_tile * I0
        tile_i_size = min(I0, I - tile_i_start)
        w_tile = sbm.alloc_heap(
            (tile_i_size, num_h_tiles, H0),
            dtype=weight.dtype,
            buffer=nl.sbuf,
            name=f"down_{sbm.get_name_prefix()}gemv_w_tile{i_tile}",
        )
        weight_view = weight.slice(
            dim=0, start=tile_i_start, end=tile_i_start + tile_i_size
        ).reshape_dim(dim=1, shape=(num_h_tiles, H0))
        nisa.dma_copy(
            dst=w_tile,
            src=weight_view.get_view(),
            dge_mode=nisa.dge_mode.swdge,
        )
        w_tiles.append((w_tile, tile_i_size))

    psum_all = nl.ndarray(
        (H0, MAX_PSUM_BANKS, 512),
        dtype=nl.float32,
        buffer=nl.psum,
        name=f"down_{sbm.get_name_prefix()}psum_all",
        address=None if sbm.is_auto_alloc() else (0, 0),
    )

    psum_tiles = []
    for b in range(MAX_PSUM_BANKS):
        psum_tiles.append(psum_all[:, b : b + 1, :])

    for h_batch in range(num_h_batches):

        for i_tile in range(num_i_tiles):
            w_tile, tile_i_size = w_tiles[i_tile]
            for b in range(MAX_PSUM_BANKS):
                h_tile = h_batch + b * num_h_batches
                nisa.nc_matmul(
                    dst=psum_tiles[b][0:H0, 0, h_batch : h_batch + T],
                    stationary=w_tile[0:tile_i_size, h_tile, 0:H0],
                    moving=hidden[0:tile_i_size, i_tile, 0:T],
                )

    nisa.activation(
        dst=output[0:H0, 0:num_h_tiles],
        op=nl.copy,
        data=psum_all[0:H0, 0:MAX_PSUM_BANKS, 0:num_h_batches],
        scale=affinity_scale if affinity_scale is not None else 1.0,
    )

def _selective_expert_moe_tkg(
    params: MLPParameters,
    output: nl.ndarray,
) -> nl.ndarray:

    _grid_ndim, _n_prgs, _prg_id = get_verified_program_sharding_info(
        "selective_expert_moe_tkg_v3", (0, 1)
    )
    kernel_assert(
        _n_prgs == 2,
        f"selective_expert_implv3 requires LNC2 (grid=[2]), got num_shards={_n_prgs}",
    )

    H = params.hidden_tensor.shape[-1]

    need_auto_alloc = (
        H >= 16 * 1024
        or params.input_in_sbuf
        or (params.router_matmul_weights is not None)
    )
    sbm = SbufManager(
        0,
        200 * 1024,
        Logger("selective_expert_moe_tkg_v3"),
        use_auto_alloc=need_auto_alloc,
    )
    sbm.open_scope()
    sbm.set_name_prefix(params.name_prefix)

    io_dtype = params.hidden_tensor.dtype
    kernel_assert(
        params.router_matmul_weights is not None,
        "selective_expert_implv3 only supports fused routing with router_matmul_weights",
    )
    kernel_assert(
        params.gamma is not None,
        "selective_expert_implv3 requires gamma for fused routing",
    )

    _pmax = nl.tile_size.pmax
    _psum_fmax = nl.tile_size.psum_fmax
    _psum_bmax = 8
    if _pmax <= 0:
        _pmax = 128
    if _psum_fmax <= 0:
        _psum_fmax = 512

    T = params.batch_size * params.sequence_len
    H = params.hidden_size

    weight_rank = len(params.gate_proj_weights_tensor.shape)
    kernel_assert(
        weight_rank == 4,
        f"selective_expert_implv3 requires combined gate/up weights with rank 4 [E, H, 2, I], got rank {weight_rank}",
    )
    local_E, _, gate_up_dim, I = params.gate_proj_weights_tensor.shape
    kernel_assert(
        gate_up_dim == 2,
        f"selective_expert_implv3 requires combined gate/up weights with shape [E, H, 2, I], got projection dim {gate_up_dim}",
    )

    H0 = _pmax
    I0 = _pmax
    H1 = H // H0

    K = params.top_k
    _, router_E = params.router_matmul_weights.shape
    local_E = router_E

    num_128_tiles_per_I, remainderI = divmod(I, I0)
    num_total_128_tiles_per_I = num_128_tiles_per_I + int(remainderI != 0)

    max_I_shard_size = 128 * 8
    num_shards_per_I = (I + max_I_shard_size - 1) // max_I_shard_size

    real_num_shards = _n_prgs
    real_shard_id = _prg_id

    dims = MLPTKGConstantsDimensionSizes(
        _pmax=_pmax,
        _psum_fmax=_psum_fmax,
        _psum_bmax=_psum_bmax,
        T=T,
        H=H,
        I=I,
        H0=H0,
        H1=H1,
        I0=I0,
        num_shards=1,
        shard_id=0,
        H_shard=H,
        H1_shard=H1,
        H1_offset=0,
        H_per_shard=H,
        num_total_128_tiles_per_I=num_total_128_tiles_per_I,
        num_128_tiles_per_I=num_128_tiles_per_I,
        remainderI=remainderI,
        remainderIFused=remainderI,
        column_tiling_dim=64,
        column_tiling_factor=128 // 64,
        num_shards_per_I=num_shards_per_I,
        max_I_shard_size=max_I_shard_size,
        do_norm_batch_sharding=False,
        K=K,
        E=local_E,
    )

    H_full = params.hidden_size
    H_free = H_full // _pmax

    rmsnorm_input = params.hidden_tensor
    if len(params.hidden_tensor.shape) == 2:
        rmsnorm_input = params.hidden_tensor.reshape((1, T, H_full))
    rmsnorm_out = sbm.alloc_stack(
        [_pmax, T, H_free],
        dtype=io_dtype,
        buffer=nl.sbuf,
        name="rmsnorm_out",
    )
    rmsnorm_out = rmsnorm_tkg(
        input=rmsnorm_input,
        gamma=params.gamma,
        output=rmsnorm_out,
        eps=params.eps,
        hidden_actual=params.hidden_actual,
        hidden_dim_tp=False,
        no_h_interleave=False,
        sbm=sbm,
        name_prefix=f"{params.name_prefix}router_",
    )

    input_sb = rmsnorm_out

    router_in = sbm.alloc_stack(
        [_pmax, T, H_free],
        dtype=nl.bfloat16,
        buffer=nl.sbuf,
        name="router_in_f32_gamma",
    )
    nisa.tensor_copy(dst=router_in, src=rmsnorm_out)

    expert_index_sb, expert_affinities_eager = router_topk_decode(
        x=router_in,
        w=params.router_matmul_weights,
        w_bias=params.router_bias,
        act_fn=params.router_act_fn,
        k=K,
        norm_topk_prob=params.norm_topk_prob,
        x_sb_layout=XSBLayout_tp2013__1,
    )

    experts_per_core = dims.K // real_num_shards
    expert_start = real_shard_id * experts_per_core
    kernel_assert(
        dims.K % real_num_shards == 0,
        f"K={dims.K} must be divisible by num_shards={real_num_shards} for expert-sharding",
    )

    down_per_expert = sbm.alloc_stack(
        (dims.H0, experts_per_core, dims.H1_shard),
        dtype=nl.bfloat16,
        name="down_per_expert",
        buffer=nl.sbuf,
    )

    gate_up_output = sbm.alloc_stack(
        (dims.I0, dims.num_total_128_tiles_per_I, experts_per_core),
        dtype=nl.bfloat16,
        name="intermediate_state_sbuf",
        buffer=nl.sbuf,
    )

    down_output_list = []
    for local_k_idx in range(experts_per_core):
        down_sb = sbm.alloc_stack(
            (dims.H0, dims.H1_shard),
            dtype=nl.bfloat16,
            name=f"down_sbuf_{local_k_idx}",
            buffer=nl.sbuf,
        )
        down_output_list.append(down_sb)

    expert_idx = expert_index_sb

    params.use_tkg_gate_up_proj_column_tiling = False
    params.use_tkg_down_proj_column_tiling = False

    initial_gate_proj_weights_tensor = params.gate_proj_weights_tensor
    initial_down_proj_weights_tensor = params.down_proj_weights_tensor

    actual_dims_t = dims.T

    affinities_padded_sb = sbm.alloc_stack(
        (dims._pmax, dims.K),
        dtype=nl.float32,
        buffer=nl.sbuf,
        name="affinities_padded_sb",
    )
    nisa.tensor_copy(
        dst=affinities_padded_sb[0:actual_dims_t, 0 : dims.K],
        src=expert_affinities_eager,
    )

    dims.T = 1
    for token_idx in range(actual_dims_t):
        sbm.set_name_prefix(f"{params.name_prefix}T{token_idx}_")

        expert_affinity_sb = sbm.alloc_stack(
            (dims._pmax, dims.K),
            dtype=nl.float32,
            buffer=nl.sbuf,
            name="expert_affinity_sb",
        )
        stream_shuffle_broadcast(
            src=affinities_padded_sb[token_idx : token_idx + 1, 0 : dims.K],
            dst=expert_affinity_sb,
        )

        for local_k_idx in range(experts_per_core):
            expert_k_idx = expert_start + local_k_idx
            sbm.set_name_prefix(f"{params.name_prefix}T{token_idx}_K{expert_k_idx}_")

            expert_id_scalar_offset = expert_idx.ap(
                pattern=[[dims.K, 1], [1, 1]], offset=token_idx * dims.K + expert_k_idx
            )

            gate_up_weight_combined = TensorView(
                initial_gate_proj_weights_tensor
            ).select(dim=0, index=expert_id_scalar_offset)
            kernel_assert(
                len(gate_up_weight_combined.shape) == 3
                and gate_up_weight_combined.shape[1] == 2,
                f"per-expert fused gate/up weights must have shape [H, 2, I], got {gate_up_weight_combined.shape}",
            )
            params.down_proj_weights_tensor = TensorView(
                initial_down_proj_weights_tensor
            ).select(dim=0, index=expert_id_scalar_offset)

            _selective_fused_gate_up_gemv_t1(
                hidden=input_sb[:, token_idx : token_idx + 1, :],
                output=gate_up_output[:, :, local_k_idx : local_k_idx + 1],
                dims=dims,
                sbm=sbm,
                gate_up_weight=gate_up_weight_combined,
                warmup=local_k_idx
                == 0,                                                                              
            )

            down_sb = down_output_list[local_k_idx]
            _selective_down_gemv_t1(
                hidden=gate_up_output[:, :, local_k_idx : local_k_idx + 1],
                weight=params.down_proj_weights_tensor,
                output=down_sb,
                dims=dims,
                sbm=sbm,
                affinity_scale=None,
            )

            nisa.tensor_scalar(
                dst=down_sb,
                data=down_sb,
                op0=nl.multiply,
                operand0=expert_affinity_sb[:, expert_k_idx : expert_k_idx + 1],
            )

            nisa.tensor_copy(
                dst=down_per_expert[0 : dims.H0, local_k_idx, 0 : dims.H1_shard],
                src=down_sb,
            )

    dims.T = actual_dims_t

    sbm.set_name_prefix(params.name_prefix)

    H1_half = dims.H1_shard // 2

    down_per_expert_recv = sbm.alloc_stack(
        (dims.H0, experts_per_core, dims.H1_shard),
        dtype=nl.bfloat16,
        name="down_per_expert_recv",
        buffer=nl.sbuf,
    )
    nisa.sendrecv(
        dst=down_per_expert_recv,
        src=down_per_expert,
        send_to_rank=1 - real_shard_id,
        recv_from_rank=1 - real_shard_id,
        pipe_id=0,
    )

    h1_start = real_shard_id * H1_half

    if real_shard_id == 0:
        first_half = down_per_expert                    
        second_half = down_per_expert_recv                    
    else:
        first_half = down_per_expert_recv                                  
        second_half = down_per_expert                            

    output_reduced = sbm.alloc_stack(
        (dims.H0, H1_half),
        dtype=nl.bfloat16,
        name="output_reduced",
        buffer=nl.sbuf,
    )

    nisa.tensor_copy(
        dst=output_reduced[0 : dims.H0, 0:H1_half],
        src=first_half[0 : dims.H0, 0, h1_start : h1_start + H1_half],
    )

    for k_idx in range(1, experts_per_core):
        nisa.tensor_tensor(
            dst=output_reduced[0 : dims.H0, 0:H1_half],
            data1=output_reduced[0 : dims.H0, 0:H1_half],
            data2=first_half[0 : dims.H0, k_idx, h1_start : h1_start + H1_half],
            op=nl.add,
        )

    for k_idx in range(experts_per_core):
        nisa.tensor_tensor(
            dst=output_reduced[0 : dims.H0, 0:H1_half],
            data1=output_reduced[0 : dims.H0, 0:H1_half],
            data2=second_half[0 : dims.H0, k_idx, h1_start : h1_start + H1_half],
            op=nl.add,
        )

    h_offset = real_shard_id * H1_half * dims.H0                              

    output_sb = sbm.alloc_stack(
        (dims.T, H1_half * dims.H0),
        dtype=nl.bfloat16,
        buffer=nl.sbuf,
        name="tkg_moe_output_sb",
    )
    output_reduced_fp32 = sbm.alloc_stack(
        (dims.H0, H1_half),
        dtype=nl.float32,
        buffer=nl.sbuf,
        name="output_reduced_fp32",
    )
    nisa.tensor_copy(dst=output_reduced_fp32, src=output_reduced)
    for h1_idx in range(H1_half):
        psum_idx = h1_idx % dims._psum_bmax
        tp_psum = nl.ndarray(
            (dims.T, dims.H0),
            dtype=nl.float32,
            buffer=nl.psum,
            name=f"{params.name_prefix}transpose_output_{h1_idx}",
            address=(
                None if sbm.is_auto_alloc() else (0, psum_idx * dims._psum_fmax * 4)
            ),
        )
        nisa.nc_transpose(
            dst=tp_psum[0 : dims.T, 0 : dims.H0],
            data=output_reduced_fp32[0 : dims.H0, h1_idx : h1_idx + 1],
        )
        nisa.tensor_copy(
            dst=output_sb[0 : dims.T, h1_idx * dims.H0 : (h1_idx + 1) * dims.H0],
            src=tp_psum[0 : dims.T, 0 : dims.H0],
        )

    output_slice = output[0 : dims.T, h_offset : h_offset + H1_half * dims.H0]
    nisa.dma_copy(
        dst=output_slice,
        src=output_sb[0 : dims.T, 0 : H1_half * dims.H0],
    )

    sbm.close_scope()
    return output

P_MAX = 128

@nki.jit(grid=[2])
def moe_selective_v3(
    hidden_input: nl.ndarray,
    expert_gate_up_weights: nl.ndarray,
    expert_down_weights: nl.ndarray,
    expert_index: Optional[nl.ndarray] = None,
    expert_affinities: Optional[nl.ndarray] = None,
    expert_gate_up_bias: Optional[nl.ndarray] = None,
    expert_down_bias: Optional[nl.ndarray] = None,
    activation_fn: ActFnType = ActFnType.SiLU,
    output_dtype=None,
    gate_clamp_upper_limit: Optional[float] = None,
    gate_clamp_lower_limit: Optional[float] = None,
    up_clamp_upper_limit: Optional[float] = None,
    up_clamp_lower_limit: Optional[float] = None,
    output_in_sbuf: bool = False,

    gamma: Optional[nl.ndarray] = None,
    router_weights: Optional[nl.ndarray] = None,
    router_bias: Optional[nl.ndarray] = None,
    router_act_fn: RouterActFnType = RouterActFnType.SOFTMAX,
    router_pre_norm=False,
    router_mm_dtype=None,
    norm_topk_prob: bool = False,
    top_k: int = 1,
    eps: float = 1e-6,
    layer_idx: int = 0,
) -> nl.ndarray:
    assert hidden_input is not None, "hidden_input must not be None"
    assert expert_gate_up_weights is not None, "expert_gate_up_weights must not be None"
    assert expert_down_weights is not None, "expert_down_weights must not be None"

    assert (
        router_weights is not None
    ), "router_weights must be provided for fused routing mode"
    assert (
        top_k is not None and top_k > 0
    ), f"top_k must be positive in fused routing mode, got {top_k}"

    expert_params = MLPExpertParameters(
        expert_index=None,
        expert_affinities=None,
        expert_affinities_scaling_mode=ExpertAffinityScaleMode.POST_SCALE,
    )

    output_dtype = hidden_input.dtype if output_dtype is None else output_dtype
    name_prefix = f"L{layer_idx}_"

    T, H = hidden_input.shape
    assert T <= 128, "currently only batch size * seq len <= 128 is supported"
    assert (
        expert_gate_up_weights.shape[1] == H
    ), f"expert_gate_up_weights hidden dim mismatch: expected {H}, got {expert_gate_up_weights.shape[1]}"
    assert (
        len(expert_down_weights.shape) == 3
    ), f"expert_down_weights must be rank-3 [E, I, H], got shape {expert_down_weights.shape}"
    assert (
        expert_down_weights.shape[2] == H
    ), f"expert_down_weights hidden dim mismatch: expected {H}, got {expert_down_weights.shape[2]}"
    if gamma is not None:
        assert (
            gamma.shape[-1] == H
        ), f"gamma hidden dim mismatch: expected {H}, got {gamma.shape[-1]}"
    if router_weights is not None:
        assert (
            router_weights.shape[0] == H
        ), f"router_weights hidden dim mismatch: expected {H}, got {router_weights.shape[0]}"

    normed_hbm = None
    mlp_hidden = hidden_input
    mlp_gamma = gamma

    mlp_params = MLPParameters(
        hidden_tensor=mlp_hidden,
        gate_proj_weights_tensor=expert_gate_up_weights,
        up_proj_weights_tensor=expert_gate_up_weights,
        down_proj_weights_tensor=expert_down_weights,
        activation_fn=activation_fn,
        normalization_type=NormType.NO_NORM,
        gate_proj_bias_tensor=expert_gate_up_bias,
        up_proj_bias_tensor=expert_gate_up_bias,
        down_proj_bias_tensor=expert_down_bias,
        output_dtype=output_dtype,
        store_output_in_sbuf=False,
        use_tkg_gate_up_proj_column_tiling=False,
        use_tkg_down_proj_column_tiling=False,
        down_weight_transposed=False,
        expert_params=expert_params,
        gate_clamp_upper_limit=gate_clamp_upper_limit,
        gate_clamp_lower_limit=gate_clamp_lower_limit,
        up_clamp_upper_limit=up_clamp_upper_limit,
        up_clamp_lower_limit=up_clamp_lower_limit,

        router_matmul_weights=router_weights,
        router_bias=router_bias,
        router_act_fn=router_act_fn,
        norm_topk_prob=norm_topk_prob,
        gamma=mlp_gamma,
        eps=eps,
        top_k=top_k,
        normed_hbm=normed_hbm,
        name_prefix=name_prefix,
    )

    output = nl.ndarray((T, H), dtype=nl.bfloat16, buffer=nl.shared_hbm)

    _selective_expert_moe_tkg(
        mlp_params,
        output,
    )

    return output

from neuronx_distributed_inference.modules.attention.attention_base import (
    EPDispatchOption,
)

from neuronx_distributed.parallel_layers import mappings, parallel_state

_ROUTER_ACT_FN_MAP = {
    "sigmoid": RouterActFnType.SIGMOID,
    "softmax": RouterActFnType.SOFTMAX,
}

class QwenMoeTKGMegaRunner:

    def __init__(self, layer):
        self.layer = layer
        self._input_layernorm = layer.input_layernorm
        self._post_attention_layernorm = layer.post_attention_layernorm
        self._self_attn = layer.self_attn
        self._mlp = layer.mlp
        self._moe_fused_nki_kernel_enabled = bool(
            getattr(layer, "moe_fused_nki_kernel_enabled", False)
        )
        neuron_config = getattr(getattr(layer, "config", None), "neuron_config", None)
        self._attention_core = self._get_attention_core()
        self._moe_core = self._get_moe_core()
        self._tp_degree = int(getattr(neuron_config, "tp_degree", 1) or 1)
        self._replica_groups = (
            (tuple(range(self._tp_degree)),) if self._tp_degree > 1 else None
        )
        self._kernel_dtype = self._get_kernel_dtype(neuron_config)
        self._mega_reason = self._get_mega_disable_reason()
        self._mega_supported = self._mega_reason is None
        self._start_marker = ModuleMarkerStartWrapper()
        self._end_marker = ModuleMarkerEndWrapper()

    def _get_attention_core(self):
        return (
            self._self_attn.attn
            if hasattr(self._self_attn, "attn")
            else self._self_attn
        )

    def _get_moe_core(self):
        candidates = [
            self._mlp,
            getattr(self._mlp, "moe", None),
        ]
        for candidate in candidates:
            if candidate is None:
                continue
            if hasattr(candidate, "router") and hasattr(candidate, "expert_mlps"):
                return candidate
        return None

    def _get_kernel_dtype(self, neuron_config):
        if self._attention_core is not None and hasattr(
            self._attention_core, "torch_dtype"
        ):
            dtype = self._attention_core.torch_dtype
            if dtype is not None:
                return dtype
        if neuron_config is not None and hasattr(neuron_config, "torch_dtype"):
            dtype = neuron_config.torch_dtype
            if dtype is not None:
                return dtype
        return torch.bfloat16

    def _get_mega_disable_reason(self) -> Optional[str]:
        attn = self._attention_core
        if attn is None:
            return "attention core is unavailable"

        if not hasattr(attn, "get_o_proj") or not hasattr(attn.get_o_proj(), "o_proj"):
            return "attention core does not expose output projection weights"
        if not hasattr(attn, "q_layernorm") or not hasattr(attn.q_layernorm, "weight"):
            return "attention core does not expose q_layernorm weights"
        if not hasattr(attn, "k_layernorm") or not hasattr(attn.k_layernorm, "weight"):
            return "attention core does not expose k_layernorm weights"
        if not hasattr(attn, "rotary_emb"):
            return "attention core does not expose rotary_emb"
        if bool(getattr(attn, "sequence_parallel_enabled", False)):
            return "mega attention currently requires sequence_parallel_enabled=False"
        if (
            getattr(attn, "ep_dispatch_cc_option", EPDispatchOption.AR_AG)
            != EPDispatchOption.AR_AG
        ):
            return (
                "mega attention currently only supports EPDispatchOption.AR_AG, "
                f"got {getattr(attn, 'ep_dispatch_cc_option', None)}"
            )
        if int(getattr(attn, "num_key_value_heads", 0) or 0) != 1:
            return (
                "attention_block_tkg_v2 currently requires per-rank num_key_value_heads == 1, "
                f"got {getattr(attn, 'num_key_value_heads', None)}"
            )

        moe = self._moe_core
        if moe is None:
            return "MoE core does not expose router/expert_mlps"

        router = getattr(moe, "router", None)
        expert_mlps = getattr(moe, "expert_mlps", None)
        if router is None or expert_mlps is None:
            return "MoE core is missing router or expert_mlps"
        if getattr(router, "act_fn", None) not in _ROUTER_ACT_FN_MAP:
            return f"unsupported router activation {getattr(router, 'act_fn', None)}"
        top_k = int(getattr(router, "top_k", 0) or 0)
        if top_k <= 0:
            return f"invalid router top_k={top_k}"
        if top_k % 2 != 0:
            return f"top_k={top_k} must be divisible by 2 for current expert sharding"
        if bool(getattr(router, "apply_act_fn_over_topk", False)):
            return "moe_selective_v3 megakernel requires apply_act_fn_over_topk=False"
        if not hasattr(router, "weight_T") and not (
            hasattr(router, "linear_router") and hasattr(router.linear_router, "weight")
        ):
            return "router does not expose transposed or raw projection weights"

        mlp_op = getattr(expert_mlps, "mlp_op", None)
        if mlp_op is None:
            return "expert_mlps does not expose mlp_op"
        if not hasattr(mlp_op, "gate_up_proj") or not hasattr(
            mlp_op.gate_up_proj, "weight"
        ):
            return "expert_mlps.mlp_op does not expose gate_up_proj weights"
        if not hasattr(mlp_op, "down_proj") or not hasattr(mlp_op.down_proj, "weight"):
            return "expert_mlps.mlp_op does not expose down_proj weights"

        return None

    def can_run(
        self,
        hidden_states: torch.Tensor,
        attention_mask: Optional[torch.Tensor],
        position_ids: Optional[torch.LongTensor],
        past_key_value: Optional[Tuple[torch.Tensor]],
    ) -> bool:
        if not self._mega_supported:
            return False
        if past_key_value is None or len(past_key_value) != 2:
            return False
        if attention_mask is None or position_ids is None:
            return False
        if hidden_states.shape[1] != 1:
            return False
        return hidden_states.shape[0] * hidden_states.shape[1] <= 128

    def _ensure_mega_supported(self, caller: str):
        if not self._mega_supported:
            raise RuntimeError(
                f"{caller} reached without mega-kernel support: {self._mega_reason}"
            )

    def _run_baseline_attention(
        self,
        hidden_states: torch.Tensor,
        attention_mask: torch.Tensor,
        position_ids: torch.LongTensor,
        past_key_value: Tuple[torch.Tensor, torch.Tensor],
        **kwargs,
    ):
        qkv_fused_rmsnorm = None
        if self._input_layernorm:
            if bool(getattr(self.layer, "qkv_kernel_enabled", False)) and bool(
                getattr(self.layer, "qkv_kernel_fused_rmsnorm", False)
            ):
                qkv_fused_rmsnorm = self._input_layernorm
            else:
                hidden_states = self._input_layernorm(hidden_states)

        return self._self_attn(
            hidden_states=hidden_states,
            attention_mask=attention_mask,
            position_ids=position_ids,
            past_key_value=past_key_value,
            rmsnorm=qkv_fused_rmsnorm,
            **kwargs,
        )

    def _build_moe_kernel_inputs(self):
        moe = self._moe_core
        router = moe.router
        expert_mlps = moe.expert_mlps
        mlp_op = expert_mlps.mlp_op

        router_weight_t = (
            router.weight_T.data
            if hasattr(router, "weight_T")
            else router.linear_router.weight.data.transpose(0, 1).contiguous()
        )

        router_bias = None
        if hasattr(router, "linear_router") and router.linear_router.bias is not None:
            router_bias = router.linear_router.bias.data.float().unsqueeze(0)

        gate_up_weight = mlp_op.gate_up_proj.weight.data
        num_experts, hidden_size, two_i = gate_up_weight.shape
        gate_up_weight_4d = gate_up_weight.view(num_experts, hidden_size, 2, two_i // 2)

        return {
            "gamma_mlp": self._post_attention_layernorm.weight.data.unsqueeze(0),
            "router_weight_t": router_weight_t,
            "router_bias": router_bias,
            "gate_up_weight_4d": gate_up_weight_4d,
            "down_weight": mlp_op.down_proj.weight.data,
            "top_k": int(router.top_k),
            "norm_topk_prob": bool(
                getattr(
                    expert_mlps.routed_experts_mlp_config,
                    "normalize_top_k_affinities",
                    False,
                )
            ),
            "router_act_fn": _ROUTER_ACT_FN_MAP[router.act_fn],
        }

    def _launch_moe_only_mega_kernelv2(self, kernel_input, moe_inputs):

        hidden_input_2d = kernel_input.reshape(-1, kernel_input.shape[-1])
        out = moe_selective_v3[2](
            hidden_input=hidden_input_2d,
            gamma=moe_inputs["gamma_mlp"],
            router_weights=moe_inputs["router_weight_t"],
            expert_gate_up_weights=moe_inputs["gate_up_weight_4d"],
            expert_down_weights=moe_inputs["down_weight"],
            router_bias=None,
            eps=float(self.layer.config.rms_norm_eps),
            top_k=8,
            router_act_fn=moe_inputs["router_act_fn"],
            norm_topk_prob=True,
            activation_fn=ActFnType.SiLU,
        )
        return out, kernel_input

    def forward(
        self,
        hidden_states: torch.Tensor,
        attention_mask: torch.Tensor,
        position_ids: torch.LongTensor,
        past_key_value: Tuple[torch.Tensor, torch.Tensor],
        padding_mask: Optional[torch.Tensor] = None,
        **kwargs,
    ):
        self._ensure_mega_supported("QwenMoeTKGMegaRunner.forward")

        residual = hidden_states
        moe_inputs = self._build_moe_kernel_inputs()
        attn_input = self._start_marker(hidden_states)
        attn_hidden, present_key_value, cos_cache, sin_cache = (
            self._run_baseline_attention(
                hidden_states=attn_input,
                attention_mask=attention_mask,
                position_ids=position_ids,
                past_key_value=past_key_value,
                **kwargs,
            )
        )
        attn_residual = residual + attn_hidden
        moe_local, residual = self._launch_moe_only_mega_kernelv2(
            attn_residual, moe_inputs
        )
        output = mappings.reduce_from_tensor_model_parallel_region(
            moe_local, process_group=parallel_state.get_tensor_model_parallel_group()
        )
        output = output.unsqueeze(0)
        output = output + residual
        layer_output = output
        assert layer_output.dtype == torch.bfloat16
        layer_output = self._end_marker(layer_output)
        return (
            layer_output,
            present_key_value,
            cos_cache,
            sin_cache,
            None,
        )

import torch.nn.functional as F
base = _self_module
from transformers import Qwen3MoeForCausalLM
from neuronx_distributed_inference.models.model_base import NeuronBaseForCausalLM
from neuronx_distributed_inference.modules.attention.utils import manual_softmax
from neuronx_distributed_inference.models.model_wrapper import CONTEXT_ENCODING_MODEL_TAG, TOKEN_GENERATION_MODEL_TAG
__all__ = ['NeuronQwen3MoeForCausalLM']

class NeuronQwen3MoEFastTokenGenAttention(base.NeuronQwen3MoEAttention):

    def apply_rotary_embedding(self, Q: torch.Tensor, K: torch.Tensor, V: torch.Tensor, position_ids: torch.Tensor, cos_cache: Optional[torch.Tensor], sin_cache: Optional[torch.Tensor], use_polar_compatible_rope: bool):
        if use_polar_compatible_rope or self.rotary_emb is None:
            return super().apply_rotary_embedding(Q, K, V, position_ids, cos_cache, sin_cache, use_polar_compatible_rope)
        if cos_cache is None or sin_cache is None:
            cos_cache, sin_cache = self.rotary_emb(V, position_ids)
        if Q.shape[0] != 1 or Q.shape[2] != 1 or K.shape[0] != 1 or (K.shape[2] != 1):
            return super().apply_rotary_embedding(Q, K, V, position_ids, cos_cache, sin_cache, use_polar_compatible_rope)
        q_heads = Q.shape[1]
        qk = torch.cat((Q, K), dim=1)
        half_dim = qk.shape[-1] // 2
        qk_rotated_half = torch.cat((-qk[..., half_dim:], qk[..., :half_dim]), dim=-1)
        cos = cos_cache.unsqueeze(1)
        sin = sin_cache.unsqueeze(1)
        qk = qk * cos + qk_rotated_half * sin
        Q, K = torch.split(qk, [q_heads, K.shape[1]], dim=1)
        return (Q, K, cos_cache, sin_cache)

    def prep_qkv_tensors(self, position_ids, hidden_states, past_key_value, adapter_ids=None, cos_cache=None, sin_cache=None, rmsnorm=None, skip_rope=False, residual=None, use_polar_compatible_rope=False):
        return super().prep_qkv_tensors(position_ids, hidden_states, past_key_value, adapter_ids=adapter_ids, cos_cache=cos_cache, sin_cache=sin_cache, rmsnorm=rmsnorm, skip_rope=skip_rope, residual=residual, use_polar_compatible_rope=use_polar_compatible_rope)

    def _can_use_fast_qwen_tkg_attention(self, Q: torch.Tensor, K: torch.Tensor, V: torch.Tensor, position_ids: Optional[torch.LongTensor], past_key_value: Optional[Tuple[torch.Tensor, torch.Tensor]], attention_mask: torch.Tensor, active_mask: Optional[torch.Tensor], is_prefix_caching: bool) -> bool:
        if is_prefix_caching:
            return False
        if past_key_value is None or position_ids is None:
            return False
        if self.get_learned_sinks() is not None:
            return False
        if Q.shape[0] != 1 or Q.shape[2] != 1:
            return False
        if K.shape[0] != 1 or K.shape[1] != 1 or K.shape[2] != 1:
            return False
        if V.shape[0] != 1 or V.shape[1] != 1 or V.shape[2] != 1:
            return False
        if past_key_value[0].shape[0] != 1 or past_key_value[0].shape[1] != 1:
            return False
        if past_key_value[1].shape[0] != 1 or past_key_value[1].shape[1] != 1:
            return False
        return Q.shape[0] == 1 and Q.shape[2] == 1

    def _flatten_attention_mask_for_fast_qwen_tkg(self, attention_mask: torch.Tensor, num_heads: int, prior_len: int) -> torch.Tensor:
        mask = attention_mask[:, :, :, :prior_len]
        if prior_len > attention_mask.shape[-1] and self.neuron_config.apply_seq_ids_mask:
            mask = F.pad(mask, (0, prior_len - attention_mask.shape[-1]), 'constant', 0)
        if mask.shape[1] == 1:
            return mask[0, 0, 0, :].reshape(1, prior_len).expand(num_heads, prior_len)
        return mask[0, :, 0, :]

    def _compute_for_token_gen_fast(self, Q: torch.Tensor, K: torch.Tensor, V: torch.Tensor, position_ids: torch.LongTensor, past_key_value: Tuple[torch.Tensor, torch.Tensor], attention_mask: torch.Tensor, active_mask: Optional[torch.Tensor]) -> torch.Tensor:
        num_heads = Q.shape[1]
        head_dim = Q.shape[-1]
        q_2d = Q[0, :, 0, :]
        if not self.k_cache_transposed:
            k_prior_2d = past_key_value[0][0, 0, :, :]
        else:
            k_prior_2d = past_key_value[0][0, 0, :, :].transpose(0, 1)
        v_prior_2d = past_key_value[1][0, 0, :, :]
        k_active_2d = K[0, 0, :, :]
        v_active_2d = V[0, 0, :, :]
        prior_scores = torch.matmul(q_2d, k_prior_2d.transpose(0, 1)) / self.softmax_scale
        prior_mask = self._flatten_attention_mask_for_fast_qwen_tkg(attention_mask, num_heads, prior_scores.shape[-1])
        prior_scores = torch.where(prior_mask, prior_scores, torch.finfo(prior_scores.dtype).min)
        active_scores = torch.matmul(q_2d, k_active_2d.transpose(0, 1)) / self.softmax_scale
        prior_scores = prior_scores.to(torch.float32)
        active_scores = active_scores.to(torch.float32)
        softmax_prior, softmax_active = manual_softmax(prior_scores, active_scores, False)
        softmax_prior, softmax_active = (softmax_prior.to(Q.dtype), softmax_active.to(Q.dtype))
        attn_prior = torch.matmul(softmax_prior, v_prior_2d)
        attn_active = torch.matmul(softmax_active, v_active_2d)
        attn_output = attn_prior + attn_active
        return attn_output.reshape(1, num_heads, 1, head_dim)

    def compute_for_token_gen(self, Q: torch.Tensor, K: torch.Tensor, V: torch.Tensor, position_ids: Optional[torch.LongTensor], past_key_value: Tuple[torch.Tensor, torch.Tensor], attention_mask: torch.Tensor, active_mask: Optional[torch.Tensor], is_prefix_caching: bool=False) -> torch.Tensor:
        if self._can_use_fast_qwen_tkg_attention(Q, K, V, position_ids, past_key_value, attention_mask, active_mask, is_prefix_caching):
            return self._compute_for_token_gen_fast(Q, K, V, position_ids, past_key_value, attention_mask, active_mask)
        return super().compute_for_token_gen(Q, K, V, position_ids, past_key_value, attention_mask, active_mask, is_prefix_caching=is_prefix_caching)

class NeuronQwen3MoeDecoderLayer(_Bundled_kernels_qwen_with_nki_original_NeuronQwen3MoeDecoderLayer):

    def __init__(self, config: Qwen3MoeInferenceConfig, layer_idx: int):
        super().__init__(config, layer_idx)
        self.self_attn = NeuronQwen3MoEFastTokenGenAttention(config=config)
        self.config = config
        self.layer_idx = layer_idx
        self._mega_runner = QwenMoeTKGMegaRunner(self)

    def forward(self, hidden_states: torch.Tensor, attention_mask: Optional[torch.Tensor]=None, position_ids: Optional[torch.LongTensor]=None, past_key_value: Optional[Tuple[torch.Tensor]]=None, padding_mask: Optional[torch.Tensor]=None, **kwargs):
        if 'padding_mask' in kwargs:
            warnings.warn('Passing `padding_mask` is deprecated and will be removed in v4.37. Please make sure use `attention_mask` instead.`')
        if self._mega_runner.can_run(hidden_states=hidden_states, attention_mask=attention_mask, position_ids=position_ids, past_key_value=past_key_value):
            return self._mega_runner.forward(hidden_states=hidden_states, attention_mask=attention_mask, position_ids=position_ids, past_key_value=past_key_value, padding_mask=padding_mask, **kwargs)
        return super().forward(hidden_states=hidden_states, attention_mask=attention_mask, position_ids=position_ids, past_key_value=past_key_value, padding_mask=padding_mask, **kwargs)

class NeuronQwen3MoeModel(_Bundled_kernels_qwen_with_nki_original_NeuronQwen3MoeModel):

    def init_model(self, config: Qwen3MoeInferenceConfig):
        print('[qwen_with_nki_mega] Qwen3-MoE mega decode path enabled')
        self.padding_idx = config.pad_token_id
        self.vocab_size = config.vocab_size
        self.embed_tokens = base.ParallelEmbedding(config.vocab_size, config.hidden_size, self.padding_idx, dtype=config.neuron_config.torch_dtype, shard_across_embedding=True)
        self.layers = torch.nn.ModuleList([NeuronQwen3MoeDecoderLayer(config, layer_idx) for layer_idx in range(config.num_hidden_layers)])
        self.norm = base.get_rmsnorm_cls()(self.hidden_size, eps=config.rms_norm_eps)
        self.lm_head = base.ColumnParallelLinear(config.hidden_size, config.vocab_size, gather_output=False if self.on_device_sampling else True, bias=False)

class NeuronQwen3MoeForCausalLM(NeuronBaseForCausalLM):
    _model_cls = NeuronQwen3MoeModel

    @staticmethod
    def load_hf_model(model_path, **kwargs):
        return Qwen3MoeForCausalLM.from_pretrained(model_path, **kwargs)

    @classmethod
    def get_config_cls(cls):
        return Qwen3MoeInferenceConfig

    @staticmethod
    def convert_hf_to_neuron_state_dict(state_dict: dict, config: Qwen3MoeInferenceConfig) -> dict:
        return convert_qwen3_moe_hf_to_neuron_state_dict(state_dict, config)

    def enable_context_encoding(self):
        self.compile_tag = CONTEXT_ENCODING_MODEL_TAG
        super().enable_context_encoding()

    def enable_token_generation(self):
        self.compile_tag = TOKEN_GENERATION_MODEL_TAG
        super().enable_token_generation()

    def get_compiler_args(self):
        if self.compile_tag == CONTEXT_ENCODING_MODEL_TAG:
            optimization_level = '-O1'
        elif self.compile_tag == TOKEN_GENERATION_MODEL_TAG:
            optimization_level = '-O3' if self.neuron_config.moe_ep_degree > 1 else '-O1'
        compiler_args = f'--enable-saturate-infinity --enable-mixed-precision-accumulation --model-type transformer {optimization_level}'
        compiler_args += " --tensorizer-options='--enable-ccop-compute-overlap --cc-pipeline-tiling-factor=2 --disable-prefetch-block-tensors '"
        compiler_args += ' --auto-cast=none'
        compiler_args += ' --internal-enable-dge-levels vector_dynamic_offsets'
        compiler_args += " --internal-hlo2tensorizer-options='--verify-hlo=true'"
        if self.neuron_config.scratchpad_page_size:
            compiler_args += f' --hbm-scratchpad-page-size={self.neuron_config.scratchpad_page_size} '
        if self.neuron_config.attn_block_tkg_nki_kernel_enabled:
            assert self.neuron_config.attn_block_tkg_nki_kernel_cascaded_attention, 'If using attn_block_tkg_nki_kernel_enabled for Qwen3MoE you must also use attn_block_tkg_nki_kernel_cascaded_attention'
            self.neuron_config.pre_rope_rmsnorm = True
            compiler_args += ' --internal-max-instruction-limit=15000000'
        return compiler_args
